export enum RaffleStatus {
  ACTIVE = 'ACTIVE',
  FINISHED = 'FINISHED'
}

export interface Raffle {
  id: string;
  name: string;
  description: string;
  fullDescription: string;
  imageUrl: string;
  totalNumbers: number;
  soldNumbers: number;
  pricePerNumber: number;
  status: RaffleStatus;
}

export interface Ticket {
  id: string;
  raffleId: string;
  number: number;
  purchaseId: string;
}

export interface Purchase {
  id: string;
  cpf: string;
  phone: string;
  raffleId: string;
  quantity: number;
  totalValue: number;
  purchaseDate: string; // ISO string
  ticketNumbers: number[]; // Derived from tickets relation
}

export interface UserStats {
  totalSpent: number;
  totalTickets: number;
  rafflesParticipated: number;
}

import { INITIAL_RAFFLES } from './mockData';
import { Raffle, RaffleStatus, Purchase } from '../types';

// In a real app, these would come from the database
let rafflesStore: Raffle[] = [...INITIAL_RAFFLES];
let purchasesStore: Purchase[] = [];

// Helper to simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const raffleService = {
  async getAllRaffles(): Promise<Raffle[]> {
    await delay(500);
    return rafflesStore;
  },

  async getRaffleById(id: string): Promise<Raffle | undefined> {
    await delay(300);
    return rafflesStore.find(r => r.id === id);
  },

  async purchaseTickets(
    raffleId: string,
    quantity: number,
    cpf: string,
    phone: string
  ): Promise<{ success: boolean; numbers: number[]; message?: string }> {
    await delay(1500); // Simulate transaction processing

    const raffleIndex = rafflesStore.findIndex(r => r.id === raffleId);
    if (raffleIndex === -1) {
      return { success: false, numbers: [], message: 'Rifa não encontrada.' };
    }

    const raffle = rafflesStore[raffleIndex];

    if (raffle.soldNumbers + quantity > raffle.totalNumbers) {
      return { success: false, numbers: [], message: 'Quantidade indisponível.' };
    }

    // Generate random available numbers (Simulation logic)
    // In a real DB, we would query `SELECT number FROM tickets WHERE raffle_id = ID AND status = available LIMIT qty`
    // Here we just generate random numbers to simulate
    const generatedNumbers: number[] = [];
    while (generatedNumbers.length < quantity) {
      const num = Math.floor(Math.random() * raffle.totalNumbers);
      if (!generatedNumbers.includes(num)) {
        generatedNumbers.push(num);
      }
    }

    // Sort numbers for better UX
    generatedNumbers.sort((a, b) => a - b);

    // Update Raffle State
    const updatedRaffle = {
      ...raffle,
      soldNumbers: raffle.soldNumbers + quantity,
    };

    // Auto-finish logic
    if (updatedRaffle.soldNumbers >= updatedRaffle.totalNumbers) {
      updatedRaffle.status = RaffleStatus.FINISHED;
    }

    rafflesStore[raffleIndex] = updatedRaffle;

    // Create Purchase Record
    const newPurchase: Purchase = {
      id: Math.random().toString(36).substring(7),
      cpf: cpf.replace(/\D/g, ''),
      phone: phone.replace(/\D/g, ''),
      raffleId,
      quantity,
      totalValue: quantity * raffle.pricePerNumber,
      purchaseDate: new Date().toISOString(),
      ticketNumbers: generatedNumbers
    };

    purchasesStore.push(newPurchase);

    return { success: true, numbers: generatedNumbers };
  },

  async getMyTickets(cpf: string): Promise<Purchase[]> {
    await delay(800);
    const cleanCpf = cpf.replace(/\D/g, '');
    return purchasesStore.filter(p => p.cpf === cleanCpf).sort((a, b) => 
      new Date(b.purchaseDate).getTime() - new Date(a.purchaseDate).getTime()
    );
  }
};

