            <p className="text-xs text-zinc-500 mt-2 text-right">
              {raffle.soldNumbers.toLocaleString()} de {raffle.totalNumbers.toLocaleString()} cotas vendidas
            </p>
          </div>

          {raffle.status === RaffleStatus.ACTIVE ? (
            <div className="bg-zinc-900 rounded-xl p-6 border border-yellow-600/30 shadow-lg shadow-yellow-900/10 flex-1 flex flex-col">
              <div className="text-center mb-6">
                <span className="text-zinc-400 text-sm uppercase tracking-wider">Por apenas</span>
                <div className="text-4xl font-black text-white mt-1">
                  R$ {raffle.pricePerNumber.toFixed(2).replace('.', ',')}
                </div>
              </div>

              {/* Quantity Selector */}
              <div className="mb-6">
                <label className="block text-sm text-zinc-400 mb-2 font-medium">Quantas cotas você quer?</label>
                <div className="flex items-center gap-3 mb-3">
                  <button onClick={decrement} className="w-12 h-12 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-white transition-colors">
                    <Minus size={20} />
                  </button>
                  <input 
                    type="number" 
                    value={quantity}
                    onChange={(e) => handleQuantityChange(e.target.value)}
                    className="flex-1 bg-black border border-zinc-700 rounded-lg h-12 text-center text-xl font-bold text-white focus:border-yellow-500 outline-none"
                  />
                  <button onClick={increment} className="w-12 h-12 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-white transition-colors">
                    <Plus size={20} />
                  </button>
                </div>

                {/* Quick select */}
                <div className="flex flex-wrap gap-2">
                  {quickOptions.map(opt => (
                    <button
                      key={opt}
                      onClick={() => setQuantity(opt)}
                      className={`px-3 py-1 rounded-full text-xs font-bold border transition-all ${
                        quantity === opt 
                        ? 'bg-yellow-600 border-yellow-600 text-black' 
                        : 'bg-transparent border-zinc-700 text-zinc-400 hover:border-yellow-500 hover:text-yellow-500'
                      }`}
                    >
                      +{opt}
                    </button>
                  ))}
                </div>
              </div>

              <div className="mt-auto pt-6 border-t border-zinc-800">
                <div className="flex justify-between items-end mb-4">
                  <span className="text-zinc-400">Total</span>
                  <span className="text-3xl font-bold text-yellow-500">
                    R$ {(quantity * raffle.pricePerNumber).toFixed(2).replace('.', ',')}
                  </span>
                </div>
                <button 
                  onClick={() => onBuy(quantity)}
                  className="w-full py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl text-lg flex items-center justify-center gap-2 shadow-lg shadow-green-900/30 transition-all hover:scale-[1.02]"
                >
                  <ShoppingCart size={24} />
                  Comprar {quantity} Cotas
                </button>
              </div>
            </div>
          ) : (
            <div className="bg-zinc-800 rounded-xl p-8 flex flex-col items-center justify-center text-center h-full opacity-75">
              <h2 className="text-2xl font-bold text-white mb-2">Ação Finalizada</h2>
              <p className="text-zinc-400">Todas as cotas foram vendidas ou o sorteio já foi realizado.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Search, Ticket as TicketIcon, Calendar, DollarSign, Package } from 'lucide-react';
import { raffleService } from '../services/raffleService';
import { Purchase } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

export const MyTickets: React.FC = () => {
  const [cpf, setCpf] = useState('');
  const [loading, setLoading] = useState(false);
  const [purchases, setPurchases] = useState<Purchase[] | null>(null);
  const [searched, setSearched] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cpf.length < 11) return;

    setLoading(true);
    try {
      const result = await raffleService.getMyTickets(cpf);
      setPurchases(result);
      setSearched(true);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  // Stats for the chart
  const stats = purchases ? [
    { name: 'Total Investido', value: purchases.reduce((acc, curr) => acc + curr.totalValue, 0) },
  ] : [];

  const chartData = purchases ? purchases.reduce((acc: any[], curr) => {
    const existing = acc.find(item => item.name === curr.raffleId); // Using ID as name simplistically
    if(existing) {
        existing.value += curr.quantity;
    } else {
        acc.push({ name: `Rifa #${curr.raffleId}`, value: curr.quantity });
    }
    return acc;
  }, []) : [];

  const COLORS = ['#eab308', '#a16207', '#facc15', '#ca8a04'];

  return (
    <div className="max-w-4xl mx-auto min-h-[60vh] animate-in fade-in duration-500">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-white mb-4">Meus Bilhetes</h2>
        <p className="text-zinc-400">Consulte seus números da sorte utilizando seu CPF.</p>
      </div>

      <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6 md:p-8 mb-8">
        <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <label className="block text-sm text-zinc-400 mb-2">CPF do Participante</label>
            <input 
              type="text" 
              value={cpf}
              onChange={(e) => setCpf(e.target.value)}
              placeholder="Digite apenas números"
              className="w-full bg-black border border-zinc-700 rounded-xl px-4 py-3 text-white focus:border-yellow-600 outline-none"
            />
          </div>
          <button 
            type="submit"
            disabled={loading}
            className="md:mt-7 px-8 py-3 bg-yellow-600 hover:bg-yellow-500 text-black font-bold rounded-xl transition-colors flex items-center justify-center gap-2"
          >
            {loading ? 'Buscando...' : (
              <>
                <Search size={20} /> Consultar
              </>
            )}
          </button>
        </form>
      </div>

      {searched && purchases && purchases.length === 0 && (
        <div className="text-center py-12 text-zinc-500">
          <TicketIcon className="w-16 h-16 mx-auto mb-4 opacity-50" />
          <p className="text-lg">Nenhum bilhete encontrado para este CPF.</p>
        </div>
      )}

      {purchases && purchases.length > 0 && (
        <div className="space-y-6">
          {/* Stats Section */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
            <div className="bg-zinc-900 p-4 rounded-xl border border-zinc-800 flex items-center gap-4">
                <div className="p-3 bg-yellow-900/20 rounded-lg text-yellow-500"><DollarSign /></div>
                <div>
                    <p className="text-zinc-500 text-xs">Total Investido</p>
                    <p className="text-white font-bold text-lg">R$ {stats[0].value.toFixed(2)}</p>
                </div>
            </div>
            <div className="bg-zinc-900 p-4 rounded-xl border border-zinc-800 flex items-center gap-4">
                <div className="p-3 bg-yellow-900/20 rounded-lg text-yellow-500"><TicketIcon /></div>
                <div>
                    <p className="text-zinc-500 text-xs">Bilhetes Comprados</p>
                    <p className="text-white font-bold text-lg">{purchases.reduce((acc, p) => acc + p.quantity, 0)}</p>
                </div>
            </div>
             <div className="bg-zinc-900 p-4 rounded-xl border border-zinc-800 flex items-center gap-4">
                <div className="p-3 bg-yellow-900/20 rounded-lg text-yellow-500"><Package /></div>
                <div>
                    <p className="text-zinc-500 text-xs">Rifas Participadas</p>
                    <p className="text-white font-bold text-lg">{new Set(purchases.map(p => p.raffleId)).size}</p>
                </div>
            </div>
          </div>

          {/* Simple Chart */}
          <div className="bg-zinc-900 p-6 rounded-xl border border-zinc-800 h-64 w-full flex flex-col items-center">
             <h3 className="text-zinc-400 text-sm mb-4">Distribuição de Cotas</h3>
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                        data={chartData}
                        cx="50%"
                        cy="50%"
                        innerRadius={60}
                        outerRadius={80}
                        paddingAngle={5}
                        dataKey="value"
                    >
                        {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#18181b', border: '1px solid #27272a', borderRadius: '8px' }}
                        itemStyle={{ color: '#fff' }}
                    />
                </PieChart>
             </ResponsiveContainer>
          </div>

          <h3 className="text-xl font-bold text-white mt-8 mb-4">Histórico de Compras</h3>

          {purchases.map((purchase) => (
            <div key={purchase.id} className="bg-zinc-900 border border-zinc-800 rounded-xl overflow-hidden">
              <div className="bg-zinc-950 px-6 py-4 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-zinc-800">
                <div>
                  <p className="text-xs text-zinc-500 mb-1">DATA DA COMPRA</p>
                  <div className="flex items-center gap-2 text-white">
                    <Calendar size={14} className="text-yellow-600" />
                    {new Date(purchase.purchaseDate).toLocaleDateString('pt-BR')}
                  </div>
                </div>
                <div>
                  <p className="text-xs text-zinc-500 mb-1">QUANTIDADE</p>
                  <p className="text-white font-bold">{purchase.quantity} Cotas</p>
                </div>
                 <div>
                  <p className="text-xs text-zinc-500 mb-1">TOTAL</p>
                  <p className="text-yellow-500 font-bold">R$ {purchase.totalValue.toFixed(2)}</p>
                </div>
              </div>

              <div className="p-6">
                <p className="text-sm text-zinc-400 mb-3">Seus números:</p>
                <div className="flex flex-wrap gap-2">
                  {purchase.ticketNumbers.map(num => (
                    <span key={num} className="bg-black border border-zinc-700 text-zinc-200 px-3 py-1 rounded text-sm font-mono">
                      {String(num).padStart(6, '0')}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { HeroCarousel } from './components/HeroCarousel';
import { RaffleCard } from './components/RaffleCard';
import { RaffleDetails } from './components/RaffleDetails';
import { CheckoutModal } from './components/CheckoutModal';
import { SuccessView } from './components/SuccessView';
import { MyTickets } from './components/MyTickets';
import { raffleService } from './services/raffleService';
import { Raffle, RaffleStatus } from './types';
import { Trophy, ShieldCheck, HeartHandshake } from 'lucide-react';

type ViewState = 'home' | 'details' | 'my-tickets' | 'success';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [selectedRaffle, setSelectedRaffle] = useState<Raffle | null>(null);
  const [raffles, setRaffles] = useState<Raffle[]>([]);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [purchaseQty, setPurchaseQty] = useState(1);
  const [purchasedNumbers, setPurchasedNumbers] = useState<number[]>([]);

  useEffect(() => {
    loadRaffles();
  }, []);

  const loadRaffles = async () => {
    const data = await raffleService.getAllRaffles();
    setRaffles(data);
  };

  const handleRaffleClick = (raffle: Raffle) => {
    setSelectedRaffle(raffle);
    setView('details');
    window.scrollTo(0, 0);
  };

  const handleBuyClick = (qty: number) => {
    setPurchaseQty(qty);
    setIsCheckoutOpen(true);
  };

  const handlePurchaseSuccess = (numbers: number[]) => {
    setIsCheckoutOpen(false);
    setPurchasedNumbers(numbers);
    setView('success');
    window.scrollTo(0, 0);
    loadRaffles(); // Refresh data
  };

  const activeRaffles = raffles.filter(r => r.status === RaffleStatus.ACTIVE);
  const finishedRaffles = raffles.filter(r => r.status === RaffleStatus.FINISHED);

  return (
    <div className="min-h-screen flex flex-col bg-zinc-950 font-sans selection:bg-yellow-500 selection:text-black">
      <Navbar onNavigate={(v) => {
        setView(v);
        window.scrollTo(0, 0);
      }} />

      <main className="flex-1 pb-20">
        {view === 'home' && (
          <div className="space-y-12 animate-in fade-in duration-500">
            <HeroCarousel />

            <div className="max-w-6xl mx-auto px-4">
              {/* Features */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-16 mt-8">
                <div className="bg-zinc-900/50 border border-zinc-800 p-6 rounded-xl flex items-center gap-4">
                  <Trophy className="text-yellow-500 w-10 h-10" />
                  <div>
                    <h3 className="font-bold text-white">Prêmios Incríveis</h3>
                    <p className="text-sm text-zinc-400">Carros, motos e eletrônicos</p>
                  </div>
                </div>
                <div className="bg-zinc-900/50 border border-zinc-800 p-6 rounded-xl flex items-center gap-4">
                  <ShieldCheck className="text-yellow-500 w-10 h-10" />
                  <div>
                    <h3 className="font-bold text-white">100% Seguro</h3>
                    <p className="text-sm text-zinc-400">Sorteio pela Loteria Federal</p>
                  </div>
                </div>
                <div className="bg-zinc-900/50 border border-zinc-800 p-6 rounded-xl flex items-center gap-4">
                  <HeartHandshake className="text-yellow-500 w-10 h-10" />
                  <div>
                    <h3 className="font-bold text-white">Baixo Custo</h3>
                    <p className="text-sm text-zinc-400">Chances reais por centavos</p>
                  </div>
                </div>
              </div>

              {/* Active Raffles */}
              <section className="mb-16">
                <div className="flex items-center gap-3 mb-8">
                  <div className="w-1.5 h-8 bg-yellow-500 rounded-full"></div>
                  <h2 className="text-3xl font-black text-white">Rifas Ativas</h2>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {activeRaffles.map(raffle => (
                    <RaffleCard key={raffle.id} raffle={raffle} onClick={handleRaffleClick} />
                  ))}
                </div>
              </section>

              {/* Finished Raffles */}
              {finishedRaffles.length > 0 && (
                <section>
                  <div className="flex items-center gap-3 mb-8 opacity-75">
                     <div className="w-1.5 h-8 bg-zinc-700 rounded-full"></div>
                    <h2 className="text-3xl font-black text-white">Rifas Finalizadas</h2>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 opacity-75 grayscale hover:grayscale-0 transition-all duration-500">
                    {finishedRaffles.map(raffle => (
                      <RaffleCard key={raffle.id} raffle={raffle} onClick={handleRaffleClick} />
                    ))}
                  </div>
                </section>
              )}
            </div>
          </div>
        )}

        {view === 'details' && selectedRaffle && (
          <div className="max-w-6xl mx-auto px-4 py-8">
            <RaffleDetails 
              raffle={selectedRaffle} 
              onBack={() => setView('home')}
              onBuy={handleBuyClick}
            />
          </div>
        )}

        {view === 'my-tickets' && (
          <div className="max-w-6xl mx-auto px-4 py-8">
            <div className="mb-6">
                 <button 
                  onClick={() => setView('home')}
                  className="flex items-center gap-2 text-zinc-400 hover:text-white transition-colors"
                >
                  <ArrowBackIcon /> Voltar para Home
                </button>
            </div>
            <MyTickets />
          </div>
        )}

        {view === 'success' && selectedRaffle && (
          <div className="max-w-4xl mx-auto px-4 py-8">
            <SuccessView 
              raffleName={selectedRaffle.name} 
              numbers={purchasedNumbers}
              onHome={() => setView('home')}
              onMyTickets={() => setView('my-tickets')}
            />
          </div>
        )}
      </main>

      <footer className="bg-black border-t border-zinc-900 py-8 text-center text-zinc-600 text-sm">
        <p className="mb-2">© 2024 BRABO PREMIAÇÕES. Todos os direitos reservados.</p>
        <p>Desenvolvido para demonstração.</p>
      </footer>

      {isCheckoutOpen && selectedRaffle && (
        <CheckoutModal 
          raffle={selectedRaffle} 
          quantity={purchaseQty} 
          onClose={() => setIsCheckoutOpen(false)}
          onSuccess={handlePurchaseSuccess}
        />
      )}
    </div>
  );
};

const ArrowBackIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
);

export default App;

import React, { useState } from 'react';
import { X, QrCode, Copy, Check, Loader2, AlertCircle } from 'lucide-react';
import { Raffle } from '../types';
import { raffleService } from '../services/raffleService';

interface CheckoutModalProps {
  raffle: Raffle;
  quantity: number;
  onClose: () => void;
  onSuccess: (numbers: number[]) => void;
}

enum CheckoutStep {
  FORM = 'FORM',
  PAYMENT = 'PAYMENT',
  PROCESSING = 'PROCESSING'
}

export const CheckoutModal: React.FC<CheckoutModalProps> = ({ raffle, quantity, onClose, onSuccess }) => {
  const [step, setStep] = useState<CheckoutStep>(CheckoutStep.FORM);
  const [cpf, setCpf] = useState('');
  const [phone, setPhone] = useState('');
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const totalValue = quantity * raffle.pricePerNumber;

  const handleGeneratePix = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cpf.length < 11 || phone.length < 10) {
      setError('Por favor preencha os dados corretamente.');
      return;
    }
    setError(null);
    setStep(CheckoutStep.PAYMENT);

    // Simulate User paying after 5 seconds in demo
    // In real world, we would poll an API endpoint checking payment status
    setTimeout(() => {
        handleConfirmPayment();
    }, 5000);
  };

  const handleConfirmPayment = async () => {
    setStep(CheckoutStep.PROCESSING);
    try {
      const result = await raffleService.purchaseTickets(raffle.id, quantity, cpf, phone);
      if (result.success) {
        onSuccess(result.numbers);
      } else {
        setError(result.message || 'Erro ao processar compra.');
        setStep(CheckoutStep.FORM);
      }
    } catch (err) {
      setError('Erro de conexão. Tente novamente.');
      setStep(CheckoutStep.FORM);
    }
  };

  const copyPix = () => {
    // Fake PIX string
    const pixCode = "00020126580014BR.GOV.BCB.PIX0136123e4567-e89b-12d3-a456-426614174000520400005303986540510.005802BR5913BRABO PREMIOS6008BRASILIA62070503***6304E2CA";
    navigator.clipboard.writeText(pixCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm">
      <div className="bg-zinc-900 border border-zinc-800 w-full max-w-md rounded-2xl overflow-hidden shadow-2xl relative">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 text-zinc-500 hover:text-white transition-colors"
        >
          <X size={24} />
        </button>

        <div className="p-6">
          <h2 className="text-2xl font-bold text-white mb-1">Finalizar Compra</h2>
          <p className="text-zinc-400 text-sm mb-6">
            Você está comprando <strong className="text-yellow-500">{quantity} cotas</strong> da rifa <span className="text-white">{raffle.name}</span>
          </p>

          {step === CheckoutStep.FORM && (
            <form onSubmit={handleGeneratePix} className="space-y-4">
               {error && (
                <div className="p-3 bg-red-900/30 border border-red-800 rounded-lg text-red-200 text-sm flex items-center gap-2">
                  <AlertCircle size={16} /> {error}
                </div>
              )}

              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">CPF (apenas números)</label>
                <input
                  type="text"
                  required
                  placeholder="000.000.000-00"
                  value={cpf}
                  onChange={(e) => setCpf(e.target.value)}
                  className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-3 text-white focus:border-yellow-600 focus:ring-1 focus:ring-yellow-600 outline-none transition-all"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">Telefone / WhatsApp</label>
                <input
                  type="tel"
                  required
                  placeholder="(00) 00000-0000"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-3 text-white focus:border-yellow-600 focus:ring-1 focus:ring-yellow-600 outline-none transition-all"
                />
              </div>

              <div className="pt-4 border-t border-zinc-800 flex justify-between items-center">
                <span className="text-zinc-400">Total a pagar:</span>
                <span className="text-2xl font-bold text-yellow-500">R$ {totalValue.toFixed(2).replace('.', ',')}</span>
              </div>

              <button 
                type="submit"
                className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-green-900/20 active:scale-95 mt-4"
              >
                Gerar Pagamento Pix
              </button>
            </form>
          )}

          {step === CheckoutStep.PAYMENT && (
            <div className="flex flex-col items-center text-center space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="w-16 h-16 bg-green-900/30 rounded-full flex items-center justify-center text-green-500 mb-2">
                <QrCode size={32} />
              </div>

              <div>
                <h3 className="text-lg font-bold text-white">Escaneie o QR Code</h3>
                <p className="text-sm text-zinc-400">Abra o app do seu banco e pague via Pix.</p>
              </div>

              {/* Fake QR Code */}
              <div className="bg-white p-2 rounded-lg">
                <img 
                  src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=BRABO-RIFAS-${raffle.id}-${quantity}`} 
                  alt="QR Code Pix" 
                  className="w-48 h-48"
                />
              </div>

              <div className="w-full">
                <p className="text-xs text-zinc-500 mb-2">Ou copie e cole o código abaixo:</p>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    readOnly 
                    value="00020126580014BR.GOV.BCB.PIX0136123e4567..." 
                    className="flex-1 bg-black border border-zinc-800 rounded-lg px-3 py-2 text-zinc-400 text-sm truncate"
                  />
                  <button 
                    onClick={copyPix}
                    className="bg-zinc-800 hover:bg-zinc-700 text-white px-3 py-2 rounded-lg transition-colors"
                  >
                    {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
                  </button>
                </div>
              </div>

