export enum RaffleStatus {
  ACTIVE = 'ACTIVE',
  FINISHED = 'FINISHED'
}

export interface Raffle {
  id: string;
  name: string;
  description: string;
  fullDescription: string;
  imageUrl: string;
  totalNumbers: number;
  soldNumbers: number;
  pricePerNumber: number;
  status: RaffleStatus;
  winnerNumber?: number | null;
  winnerName?: string | null;
}

export interface Purchase {
  id: string;
  cpf: string;
  phone: string;
  raffleId: string;
  raffleName?: string; // For admin display
  quantity: number;
  totalValue: number;
  purchaseDate: string;
  ticketNumbers: number[]; 
}

export interface Banner {
  id: string;
  image_url: string;
  active: boolean;
}

// Helper type for Supabase raw response if needed
export interface DB_Purchase {
  id: string;
  raffle_id: string;
  cpf: string;
  phone: string;
  quantity: number;
  total_value: number;
  purchase_date: string;
}

import { supabase } from './supabaseClient';
import { Raffle, RaffleStatus, Purchase, Banner } from '../types';
import { HERO_IMAGES } from './mockData';

export const raffleService = {
  // --- PUBLIC METHODS ---

  async getBanners(): Promise<string[]> {
    const { data, error } = await supabase
      .from('banners')
      .select('image_url')
      .eq('active', true)
      .order('created_at', { ascending: false });

    if (error || !data || data.length === 0) {
      return HERO_IMAGES; // Fallback to mock data if table is empty or missing
    }
    return data.map(b => b.image_url);
  },

  async getAllRaffles(): Promise<Raffle[]> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw error;

    const rafflesWithCount = await Promise.all(data.map(async (r: any) => {
        // Optimization: In prod, use a trigger to update a 'sold_count' column on raffle table
        const { count } = await supabase
            .from('tickets')
            .select('*', { count: 'exact', head: true })
            .eq('raffle_id', r.id);

        return {
            id: r.id,
            name: r.name,
            description: r.description,
            fullDescription: r.full_description,
            imageUrl: r.image_url,
            totalNumbers: r.total_numbers,
            soldNumbers: count || 0,
            pricePerNumber: r.price_per_number,
            status: r.status as RaffleStatus,
            winnerNumber: r.winner_number,
            winnerName: r.winner_name
        };
    }));

    return rafflesWithCount;
  },

  async getRaffleById(id: string): Promise<Raffle | undefined> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .eq('id', id)
      .single();

    if (error || !data) return undefined;

    const { count } = await supabase
        .from('tickets')
        .select('*', { count: 'exact', head: true })
        .eq('raffle_id', id);

    return {
        id: data.id,
        name: data.name,
        description: data.description,
        fullDescription: data.full_description,
        imageUrl: data.image_url,
        totalNumbers: data.total_numbers,
        soldNumbers: count || 0,
        pricePerNumber: data.price_per_number,
        status: data.status as RaffleStatus,
        winnerNumber: data.winner_number,
        winnerName: data.winner_name
    };
  },

  async purchaseTickets(
    raffleId: string,
    quantity: number,
    cpf: string,
    phone: string
  ): Promise<{ success: boolean; numbers: number[]; message?: string }> {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    const raffle = await this.getRaffleById(raffleId);
    if (!raffle) return { success: false, numbers: [], message: 'Rifa não encontrada.' };

    if (raffle.soldNumbers + quantity > raffle.totalNumbers) {
      return { success: false, numbers: [], message: 'Quantidade indisponível.' };
    }

    const generatedNumbers: number[] = [];
    let attempts = 0;
    const maxAttempts = quantity * 5;

    while (generatedNumbers.length < quantity && attempts < maxAttempts) {
        attempts++;
        const candidate = Math.floor(Math.random() * raffle.totalNumbers);
        if (generatedNumbers.includes(candidate)) continue;

        const { data } = await supabase
            .from('tickets')
            .select('number')
            .eq('raffle_id', raffleId)
            .eq('number', candidate)
            .single();

        if (!data) {
            generatedNumbers.push(candidate);
        }
    }

    if (generatedNumbers.length < quantity) {
        return { success: false, numbers: [], message: 'Erro ao gerar números. Tente novamente.' };
    }
    generatedNumbers.sort((a, b) => a - b);

    const { data: purchaseData, error: purchaseError } = await supabase
        .from('purchases')
        .insert({
            raffle_id: raffleId,
            cpf: cleanCpf,
            phone: cleanPhone,
            quantity: quantity,
            total_value: quantity * raffle.pricePerNumber
        })
        .select()
        .single();

    if (purchaseError || !purchaseData) {
        console.error(purchaseError);
        return { success: false, numbers: [], message: 'Erro ao registrar compra.' };
    }

    const ticketsPayload = generatedNumbers.map(num => ({
        raffle_id: raffleId,
        purchase_id: purchaseData.id,
        number: num,
        owner_cpf: cleanCpf
    }));

    const { error: ticketsError } = await supabase.from('tickets').insert(ticketsPayload);

    if (ticketsError) {
        console.error(ticketsError);
        return { success: false, numbers: [], message: 'Erro crítico ao gerar bilhetes.' };
    }

    if (raffle.soldNumbers + quantity >= raffle.totalNumbers) {
         await supabase.from('raffles').update({ status: 'FINISHED' }).eq('id', raffleId);
    }

    return { success: true, numbers: generatedNumbers };
  },

  async getMyTickets(cpf: string): Promise<Purchase[]> {
    const cleanCpf = cpf.replace(/\D/g, '');

    const { data: purchases, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .eq('cpf', cleanCpf)
        .order('purchase_date', { ascending: false });

    if (error) return [];

    const fullPurchases = await Promise.all(purchases.map(async (p: any) => {
        const { data: tickets } = await supabase
            .from('tickets')
            .select('number')
            .eq('purchase_id', p.id);

        return {
            id: p.id,
            cpf: p.cpf,
            phone: p.phone,
            raffleId: p.raffle_id,
            raffleName: p.raffles?.name,
            quantity: p.quantity,
            totalValue: p.total_value,
            purchaseDate: p.purchase_date,
            ticketNumbers: tickets?.map((t: any) => t.number).sort((a: number, b: number) => a - b) || []
        };
    }));

    return fullPurchases;
  },

  // --- ADMIN METHODS ---

  async adminGetStats() {
      const { data: purchases } = await supabase.from('purchases').select('total_value');
      const totalRevenue = purchases?.reduce((acc, curr) => acc + (curr.total_value || 0), 0) || 0;

      const { count: activeRaffles } = await supabase.from('raffles').select('*', { count: 'exact', head: true }).eq('status', 'ACTIVE');
      const { count: totalTickets } = await supabase.from('tickets').select('*', { count: 'exact', head: true });

      // Calculate Average Ticket
      const avgTicket = purchases && purchases.length > 0 ? totalRevenue / purchases.length : 0;

      return { totalRevenue, activeRaffles, totalTickets, avgTicket };
  },

  // Banner Management
  async adminGetBanners() {
      const { data } = await supabase.from('banners').select('*').order('created_at', { ascending: false });
      return data || [];
  },

  async adminCreateBanner(imageUrl: string) {
      return await supabase.from('banners').insert({ image_url: imageUrl, active: true });
  },

  async adminDeleteBanner(id: string) {
      return await supabase.from('banners').delete().eq('id', id);
  },

  // Raffle Management
  async createRaffle(data: Partial<Raffle>) {
      const payload = {
          name: data.name,
          description: data.description,
          full_description: data.fullDescription,
          image_url: data.imageUrl,
          total_numbers: data.totalNumbers,
          price_per_number: data.pricePerNumber,
          status: 'ACTIVE'
      };
      return await supabase.from('raffles').insert(payload);
  },

  async updateRaffle(id: string, updates: any) {
     return await supabase.from('raffles').update(updates).eq('id', id);
  },

  // Ticket Management
  async getTicketOwner(raffleId: string, number: number) {
      return await supabase
        .from('tickets')
        .select('*, purchases(phone, cpf, purchase_date)')
        .eq('raffle_id', raffleId)
        .eq('number', number)
        .single();
  },

  async adminUpdateTicketOwner(ticketId: string, newCpf: string) {
      // Warning: This only updates the ticket owner, not the original purchase record
      // Useful for correcting "I put the wrong CPF on this specific ticket"
      return await supabase.from('tickets').update({ owner_cpf: newCpf }).eq('id', ticketId);
  },

  // Purchases Management
  async adminGetAllPurchases(limit = 50) {
      const { data, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .order('purchase_date', { ascending: false })
        .limit(limit);

      if(error) throw error;
      return data;
  },

  async adminUpdatePurchase(purchaseId: string, updates: { phone?: string, cpf?: string }) {
      // Updates the purchase record AND all associated tickets to maintain consistency
      const { error } = await supabase.from('purchases').update(updates).eq('id', purchaseId);
      if (error) throw error;

      if (updates.cpf) {
          await supabase.from('tickets').update({ owner_cpf: updates.cpf }).eq('purchase_id', purchaseId);
      }
      return { error: null };
  },

  async adminGetRevenueChart() {
      // Mocked aggregation for demo purposes (Supabase doesn't support complex group by without RPC easily)
      // In prod: Create a Database Function for daily revenue
      const { data } = await supabase
        .from('purchases')
        .select('total_value, purchase_date')
        .order('purchase_date', { ascending: true });

      if (!data) return [];

      // Group by date (simple JS aggregation)
      const grouped: Record<string, number> = {};
      data.forEach(p => {
          const date = new Date(p.purchase_date).toLocaleDateString('pt-BR');
          grouped[date] = (grouped[date] || 0) + p.total_value;
      });

      return Object.entries(grouped).map(([date, value]) => ({ date, value }));
  }
};

import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { raffleService } from '../services/raffleService';

export const HeroCarousel: React.FC = () => {
  const [images, setImages] = useState<string[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const loadBanners = async () => {
        try {
            const fetched = await raffleService.getBanners();
            setImages(fetched);
        } catch (e) {
            console.error(e);
        }
    };
    loadBanners();
  }, []);

  useEffect(() => {
    if (images.length === 0) return;
    const timer = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 5000);
    return () => clearInterval(timer);
  }, [images]);

  const nextSlide = () => setCurrentIndex((prev) => (prev + 1) % images.length);
  const prevSlide = () => setCurrentIndex((prev) => (prev - 1 + images.length) % images.length);

  if (images.length === 0) return <div className="w-full h-[200px] md:h-[450px] bg-zinc-900 animate-pulse" />;

  return (
    <div className="relative w-full h-[200px] md:h-[450px] overflow-hidden bg-zinc-900">
      <div className="absolute inset-0 bg-black/40 z-10"></div>

      {/* Images */}
      {images.map((img, index) => (
        <div
          key={index}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
            index === currentIndex ? 'opacity-100' : 'opacity-0'
          }`}
        >
          <img src={img} alt="Banner" className="w-full h-full object-cover" />
        </div>
      ))}

      {/* Content Overlay */}
      <div className="absolute inset-0 z-20 flex flex-col items-center justify-center text-center px-4">
        <h1 className="text-2xl md:text-6xl font-black text-white mb-2 md:mb-4 drop-shadow-2xl leading-tight">
          A SORTE ESTÁ <br />
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-yellow-600">
            AO SEU LADO
          </span>
        </h1>
        <p className="text-zinc-200 text-xs md:text-xl max-w-2xl font-medium drop-shadow-md hidden md:block">
          Participe das melhores rifas do Brasil com prêmios exclusivos.
          Pagamento via Pix e resultado pela Loteria Federal.
        </p>
      </div>

      {/* Controls */}
      <button 
        onClick={prevSlide}
        className="absolute left-2 md:left-4 top-1/2 -translate-y-1/2 z-30 p-1 md:p-2 bg-black/50 hover:bg-yellow-600 rounded-full text-white transition-colors"
      >
        <ChevronLeft size={20} className="md:w-6 md:h-6" />
      </button>
      <button 
        onClick={nextSlide}
        className="absolute right-2 md:right-4 top-1/2 -translate-y-1/2 z-30 p-1 md:p-2 bg-black/50 hover:bg-yellow-600 rounded-full text-white transition-colors"
      >
        <ChevronRight size={20} className="md:w-6 md:h-6" />
      </button>

      {/* Dots */}
      <div className="absolute bottom-2 md:bottom-4 left-1/2 -translate-x-1/2 z-30 flex gap-2">
        {images.map((_, idx) => (
          <button
            key={idx}
            onClick={() => setCurrentIndex(idx)}
            className={`w-2 h-2 md:w-3 md:h-3 rounded-full transition-all ${
              idx === currentIndex ? 'bg-yellow-500 w-4 md:w-6' : 'bg-white/50'
            }`}
          />
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { raffleService } from '../services/raffleService';
import { Raffle, Purchase, Banner } from '../types';
import { 
  LayoutDashboard, 
  Plus, 
  Edit, 
  Trash2, 
  Ticket, 
  DollarSign, 
  Users, 
  LogOut, 
  Save, 
  X,
  Search,
  Trophy,
  Loader2,
  Lock,
  Image as ImageIcon,
  TrendingUp,
  ShoppingBag,
  RefreshCw
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer } from 'recharts';

export const AdminPanel: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  const [session, setSession] = useState<any>(null);
  const [loadingSession, setLoadingSession] = useState(true);

  // Login State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [loggingIn, setLoggingIn] = useState(false);

  // Tabs
  const [activeTab, setActiveTab] = useState<'dashboard' | 'raffles' | 'tickets' | 'sales' | 'site'>('dashboard');

  // Data
  const [stats, setStats] = useState({ totalRevenue: 0, activeRaffles: 0, totalTickets: 0, avgTicket: 0 });
  const [chartData, setChartData] = useState<any[]>([]);
  const [raffles, setRaffles] = useState<Raffle[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  // Raffle Form
  const [isEditing, setIsEditing] = useState<Raffle | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [formData, setFormData] = useState<any>({});

  // Ticket Manager
  const [searchTicket, setSearchTicket] = useState({ raffleId: '', number: '' });
  const [foundTicket, setFoundTicket] = useState<any>(null);
  const [newOwnerCpf, setNewOwnerCpf] = useState('');

  // Sales Manager
  const [purchases, setPurchases] = useState<any[]>([]);
  const [editPurchase, setEditPurchase] = useState<any>(null); // For modal

  // Site Manager (Banners)
  const [banners, setBanners] = useState<any[]>([]);
  const [newBannerUrl, setNewBannerUrl] = useState('');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoadingSession(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session) {
      loadDashboard();
    }
  }, [session]);

  const loadDashboard = async () => {
    setLoadingData(true);
    try {
        const s = await raffleService.adminGetStats();
        // @ts-ignore
        setStats(s);
        const r = await raffleService.getAllRaffles();
        setRaffles(r);
        const c = await raffleService.adminGetRevenueChart();
        setChartData(c);
    } catch (error) {
        console.error("Erro ao carregar dashboard", error);
    } finally {
        setLoadingData(false);
    }
  };

  // --- TAB LOADERS ---
  useEffect(() => {
      if(!session) return;
      if (activeTab === 'sales') loadPurchases();
      if (activeTab === 'site') loadBanners();
  }, [activeTab]);

  const loadPurchases = async () => {
      setLoadingData(true);
      try {
          const data = await raffleService.adminGetAllPurchases(100); // limit 100 for perf
          setPurchases(data || []);
      } catch(e) { console.error(e); } 
      finally { setLoadingData(false); }
  };

  const loadBanners = async () => {
      try {
          const data = await raffleService.adminGetBanners();
          setBanners(data);
      } catch(e) { console.error(e); }
  };

  // --- ACTIONS ---

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoggingIn(true);
    setLoginError('');
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setLoginError('Email ou senha inválidos.');
    setLoggingIn(false);
  };

  const handleSaveRaffle = async (e: React.FormEvent) => {
      e.preventDefault();
      try {
          if (isCreating) {
              await raffleService.createRaffle(formData);
          } else if (isEditing) {
              await raffleService.updateRaffle(isEditing.id, {
                  name: formData.name,
                  description: formData.description,
                  full_description: formData.fullDescription,
                  image_url: formData.imageUrl,
                  price_per_number: formData.pricePerNumber,
                  status: formData.status,
                  winner_number: formData.winnerNumber || null,
                  winner_name: formData.winnerName || null
              });
          }
          setIsCreating(false);
          setIsEditing(null);
          setFormData({});
          loadDashboard(); // Refresh
      } catch (err) {
          alert('Erro ao salvar. Verifique permissões.');
      }
  };

  const handleDeleteRaffle = async (id: string) => {
      if(!confirm('ATENÇÃO: Deletar uma rifa apaga todo histórico de vendas dela. Confirmar?')) return;
      const { error } = await supabase.from('raffles').delete().eq('id', id);
      if (error) alert('Erro ao deletar.');
      else loadDashboard();
  };

  const handleSearchTicket = async (e: React.FormEvent) => {
      e.preventDefault();
      setFoundTicket(null);
      const { data, error } = await raffleService.getTicketOwner(searchTicket.raffleId, parseInt(searchTicket.number));
      if(error || !data) setFoundTicket({ error: 'Bilhete não encontrado.' });
      else setFoundTicket(data);
  };

  const handleUpdateTicketOwner = async () => {
      if (!foundTicket || !foundTicket.id) return;
      if (!newOwnerCpf || newOwnerCpf.length < 11) return alert('CPF inválido');

      try {
          await raffleService.adminUpdateTicketOwner(foundTicket.id, newOwnerCpf);
          alert('Dono do bilhete atualizado com sucesso!');
          setFoundTicket(prev => ({...prev, owner_cpf: newOwnerCpf})); // Optimistic update
          setNewOwnerCpf('');
      } catch(e) {
          alert('Erro ao atualizar dono.');
      }
  };

  const handleUpdatePurchase = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!editPurchase) return;
      try {
          await raffleService.adminUpdatePurchase(editPurchase.id, { 
              phone: editPurchase.phone, 
              cpf: editPurchase.cpf 
          });
          setEditPurchase(null);
          loadPurchases(); // Refresh table
          alert('Dados da compra atualizados.');
      } catch(e) {
          alert('Erro ao atualizar compra.');
      }
  };

  const handleAddBanner = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!newBannerUrl) return;
      try {
          await raffleService.adminCreateBanner(newBannerUrl);
          setNewBannerUrl('');
          loadBanners();
      } catch(e) {
          alert('Erro ao adicionar banner. A tabela "banners" existe no banco?');
      }
  };

  const handleDeleteBanner = async (id: string) => {
      if(!confirm('Remover banner?')) return;
      await raffleService.adminDeleteBanner(id);
      loadBanners();
  };


  // --- VIEW ---

  if (loadingSession) return <div className="min-h-screen bg-zinc-950 flex items-center justify-center text-white"><Loader2 className="animate-spin" /></div>;

  if (!session) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-zinc-950 p-4">
        <form onSubmit={handleLogin} className="bg-zinc-900 p-8 rounded-2xl border border-zinc-800 w-full max-w-md shadow-2xl">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-yellow-900/20 rounded-full"><Lock className="w-8 h-8 text-yellow-500" /></div>
          </div>
          <h2 className="text-2xl font-bold text-white mb-2 text-center">Admin Pro</h2>
          {loginError && <div className="bg-red-900/30 border border-red-800 text-red-200 p-3 rounded mb-4 text-sm text-center">{loginError}</div>}
          <div className="space-y-4">
            <input type="email" placeholder="admin@brabo.com" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-black border border-zinc-700 rounded-lg p-3 text-white focus:border-yellow-600 outline-none" />
            <input type="password" placeholder="••••••••" value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-black border border-zinc-700 rounded-lg p-3 text-white focus:border-yellow-600 outline-none" />
          </div>
          <button disabled={loggingIn} className="w-full bg-yellow-600 hover:bg-yellow-500 text-black font-bold py-3 rounded-lg mt-6 flex justify-center">
            {loggingIn ? <Loader2 className="animate-spin" /> : 'Entrar'}
          </button>
          <button type="button" onClick={onExit} className="w-full mt-4 text-zinc-500 text-sm">Voltar ao site</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col md:flex-row text-white font-sans">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-zinc-900 border-r border-zinc-800 flex flex-col z-20">
        <div className="p-6 border-b border-zinc-800">
            <h1 className="text-xl font-bold text-yellow-500 tracking-wider">BRABO CMS</h1>
            <p className="text-xs text-zinc-500">v2.0 Ultimate</p>
        </div>

        <nav className="flex-1 p-4 space-y-1">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'raffles', icon: Ticket, label: 'Gerenciar Rifas' },
            { id: 'sales', icon: ShoppingBag, label: 'Vendas & Leads' },
            { id: 'tickets', icon: Users, label: 'Editar Bilhetes' },
            { id: 'site', icon: ImageIcon, label: 'Configurar Site' },
          ].map((item) => (
             <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${activeTab === item.id ? 'bg-yellow-600 text-black font-bold shadow-lg shadow-yellow-900/20' : 'text-zinc-400 hover:bg-zinc-800 hover:text-white'}`}
              >
                <item.icon size={18} /> {item.label}
              </button>
          ))}
        </nav>

        <div className="p-4 border-t border-zinc-800">
            <div className="flex items-center gap-3 mb-4 px-2">
                <div className="w-8 h-8 rounded-full bg-zinc-800 flex items-center justify-center text-xs font-bold">AD</div>
                <div className="overflow-hidden">
                    <p className="text-sm font-bold truncate">Admin</p>
                    <p className="text-xs text-zinc-500 truncate">{session.user.email}</p>
                </div>
            </div>
            <button onClick={async () => { await supabase.auth.signOut(); onExit(); }} className="w-full flex items-center gap-2 text-red-400 hover:bg-red-900/20 px-4 py-2 rounded-lg transition-colors">
                <LogOut size={16} /> Sair do Sistema
            </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto h-screen bg-black/50">
        <header className="bg-zinc-900/50 backdrop-blur border-b border-zinc-800 p-6 sticky top-0 z-10 flex justify-between items-center">
            <h2 className="text-2xl font-bold text-white capitalize">{activeTab.replace('-', ' ')}</h2>
            <div className="flex gap-2">
                <button onClick={() => window.location.reload()} className="p-2 text-zinc-400 hover:text-white"><RefreshCw size={20} /></button>
            </div>
        </header>

        <div className="p-6 md:p-8 max-w-7xl mx-auto">

            {/* DASHBOARD TAB */}
            {activeTab === 'dashboard' && (
                <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                        {[
                            { label: 'Faturamento Total', val: `R$ ${stats.totalRevenue.toFixed(2)}`, icon: DollarSign, color: 'text-green-500' },
                            { label: 'Ticket Médio', val: `R$ ${stats.avgTicket.toFixed(2)}`, icon: TrendingUp, color: 'text-blue-500' },
                            { label: 'Bilhetes Vendidos', val: stats.totalTickets, icon: Ticket, color: 'text-yellow-500' },
                            { label: 'Rifas Ativas', val: stats.activeRaffles, icon: RefreshCw, color: 'text-purple-500' },
                        ].map((s, i) => (
                            <div key={i} className="bg-zinc-900 border border-zinc-800 p-6 rounded-2xl flex items-center justify-between">
                                <div>
                                    <p className="text-zinc-400 text-xs font-bold uppercase mb-1">{s.label}</p>
                                    <p className="text-2xl font-bold text-white">{s.val}</p>
                                </div>
                                <div className={`p-3 rounded-xl bg-zinc-950 ${s.color}`}><s.icon /></div>
                            </div>
                        ))}
                    </div>

                    <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
                        <h3 className="text-lg font-bold text-white mb-6">Receita nos últimos dias</h3>
                        <div className="h-64 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={chartData}>
                                    <defs>
                                        <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#eab308" stopOpacity={0.3}/>
                                            <stop offset="95%" stopColor="#eab308" stopOpacity={0}/>
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#27272a" />
                                    <XAxis dataKey="date" stroke="#71717a" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis stroke="#71717a" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `R$${val}`} />
                                    <RechartsTooltip contentStyle={{ backgroundColor: '#18181b', border: '1px solid #27272a', borderRadius: '8px' }} />
                                    <Area type="monotone" dataKey="value" stroke="#eab308" strokeWidth={2} fillOpacity={1} fill="url(#colorVal)" />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>
            )}

            {/* RAFFLES TAB */}
            {activeTab === 'raffles' && (
                <div className="space-y-6 animate-in fade-in">
                    <div className="flex justify-end">
                        <button onClick={() => { setIsCreating(true); setFormData({ totalNumbers: 1000, pricePerNumber: 0.99 }); }} className="bg-green-600 hover:bg-green-500 text-white px-6 py-3 rounded-lg font-bold flex items-center gap-2 shadow-lg shadow-green-900/20">
                            <Plus size={20} /> Criar Nova Rifa
                        </button>
                    </div>

