import { supabase } from './supabaseClient';
import { Raffle, RaffleStatus, Purchase, Banner } from '../types';

export const raffleService = {
  // --- PUBLIC METHODS ---

  async getBanners(): Promise<string[]> {
    const { data, error } = await supabase
      .from('banners')
      .select('image_url')
      .eq('active', true)
      .order('created_at', { ascending: false });

    if (error || !data) {
      return []; 
    }
    return data.map(b => b.image_url);
  },

  async getAllRaffles(): Promise<Raffle[]> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw error;

    const rafflesWithCount = await Promise.all(data.map(async (r: any) => {
        // Optimization: In prod, use a trigger to update a 'sold_count' column on raffle table
        const { count } = await supabase
            .from('tickets')
            .select('*', { count: 'exact', head: true })
            .eq('raffle_id', r.id);

        return {
            id: r.id,
            name: r.name,
            description: r.description,
            fullDescription: r.full_description,
            imageUrl: r.image_url,
            totalNumbers: r.total_numbers,
            soldNumbers: count || 0,
            pricePerNumber: r.price_per_number,
            status: r.status as RaffleStatus,
            winnerNumber: r.winner_number,
            winnerName: r.winner_name
        };
    }));

    return rafflesWithCount;
  },

  async getRaffleById(id: string): Promise<Raffle | undefined> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .eq('id', id)
      .single();

    if (error || !data) return undefined;

    const { count } = await supabase
        .from('tickets')
        .select('*', { count: 'exact', head: true })
        .eq('raffle_id', id);

    return {
        id: data.id,
        name: data.name,
        description: data.description,
        fullDescription: data.full_description,
        imageUrl: data.image_url,
        totalNumbers: data.total_numbers,
        soldNumbers: count || 0,
        pricePerNumber: data.price_per_number,
        status: data.status as RaffleStatus,
        winnerNumber: data.winner_number,
        winnerName: data.winner_name
    };
  },

  async purchaseTickets(
    raffleId: string,
    quantity: number,
    cpf: string,
    phone: string
  ): Promise<{ success: boolean; numbers: number[]; message?: string }> {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    const raffle = await this.getRaffleById(raffleId);
    if (!raffle) return { success: false, numbers: [], message: 'Rifa não encontrada.' };

    if (raffle.soldNumbers + quantity > raffle.totalNumbers) {
      return { success: false, numbers: [], message: 'Quantidade indisponível.' };
    }

    const generatedNumbers: number[] = [];
    let attempts = 0;
    const maxAttempts = quantity * 5;

    while (generatedNumbers.length < quantity && attempts < maxAttempts) {
        attempts++;
        const candidate = Math.floor(Math.random() * raffle.totalNumbers);
        if (generatedNumbers.includes(candidate)) continue;

        const { data } = await supabase
            .from('tickets')
            .select('number')
            .eq('raffle_id', raffleId)
            .eq('number', candidate)
            .single();

        if (!data) {
            generatedNumbers.push(candidate);
        }
    }

    if (generatedNumbers.length < quantity) {
        return { success: false, numbers: [], message: 'Erro ao gerar números. Tente novamente.' };
    }
    generatedNumbers.sort((a, b) => a - b);

    const { data: purchaseData, error: purchaseError } = await supabase
        .from('purchases')
        .insert({
            raffle_id: raffleId,
            cpf: cleanCpf,
            phone: cleanPhone,
            quantity: quantity,
            total_value: quantity * raffle.pricePerNumber
        })
        .select()
        .single();

    if (purchaseError || !purchaseData) {
        console.error(purchaseError);
        return { success: false, numbers: [], message: 'Erro ao registrar compra.' };
    }

    const ticketsPayload = generatedNumbers.map(num => ({
        raffle_id: raffleId,
        purchase_id: purchaseData.id,
        number: num,
        owner_cpf: cleanCpf
    }));

    const { error: ticketsError } = await supabase.from('tickets').insert(ticketsPayload);

    if (ticketsError) {
        console.error(ticketsError);
        return { success: false, numbers: [], message: 'Erro crítico ao gerar bilhetes.' };
    }

    if (raffle.soldNumbers + quantity >= raffle.totalNumbers) {
         await supabase.from('raffles').update({ status: 'FINISHED' }).eq('id', raffleId);
    }

    return { success: true, numbers: generatedNumbers };
  },

  async getMyTickets(cpf: string): Promise<Purchase[]> {
    const cleanCpf = cpf.replace(/\D/g, '');

    const { data: purchases, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .eq('cpf', cleanCpf)
        .order('purchase_date', { ascending: false });

    if (error) return [];

    const fullPurchases = await Promise.all(purchases.map(async (p: any) => {
        const { data: tickets } = await supabase
            .from('tickets')
            .select('number')
            .eq('purchase_id', p.id);

        return {
            id: p.id,
            cpf: p.cpf,
            phone: p.phone,
            raffleId: p.raffle_id,
            raffleName: p.raffles?.name,
            quantity: p.quantity,
            totalValue: p.total_value,
            purchaseDate: p.purchase_date,
            ticketNumbers: tickets?.map((t: any) => t.number).sort((a: number, b: number) => a - b) || []
        };
    }));

    return fullPurchases;
  },

  // --- ADMIN METHODS ---

  async adminGetStats() {
      const { data: purchases } = await supabase.from('purchases').select('total_value');
      const totalRevenue = purchases?.reduce((acc, curr) => acc + (curr.total_value || 0), 0) || 0;

      const { count: activeRaffles } = await supabase.from('raffles').select('*', { count: 'exact', head: true }).eq('status', 'ACTIVE');
      const { count: totalTickets } = await supabase.from('tickets').select('*', { count: 'exact', head: true });

      // Calculate Average Ticket
      const avgTicket = purchases && purchases.length > 0 ? totalRevenue / purchases.length : 0;

      return { totalRevenue, activeRaffles, totalTickets, avgTicket };
  },

  // Banner Management
  async adminGetBanners() {
      const { data } = await supabase.from('banners').select('*').order('created_at', { ascending: false });
      return data || [];
  },

  async adminCreateBanner(imageUrl: string) {
      return await supabase.from('banners').insert({ image_url: imageUrl, active: true });
  },

  async adminDeleteBanner(id: string) {
      return await supabase.from('banners').delete().eq('id', id);
  },

  // Raffle Management
  async createRaffle(data: Partial<Raffle>) {
      const payload = {
          name: data.name,
          description: data.description,
          full_description: data.fullDescription,
          image_url: data.imageUrl,
          total_numbers: data.totalNumbers,
          price_per_number: data.pricePerNumber,
          status: 'ACTIVE'
      };
      return await supabase.from('raffles').insert(payload);
  },

  async updateRaffle(id: string, updates: any) {
     return await supabase.from('raffles').update(updates).eq('id', id);
  },

  // Ticket Management
  async getTicketOwner(raffleId: string, number: number) {
      return await supabase
        .from('tickets')
        .select('*, purchases(phone, cpf, purchase_date)')
        .eq('raffle_id', raffleId)
        .eq('number', number)
        .single();
  },

  async adminUpdateTicketOwner(ticketId: string, newCpf: string) {
      // Warning: This only updates the ticket owner, not the original purchase record
      // Useful for correcting "I put the wrong CPF on this specific ticket"
      return await supabase.from('tickets').update({ owner_cpf: newCpf }).eq('id', ticketId);
  },

  // Purchases Management
  async adminGetAllPurchases(limit = 50) {
      const { data, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .order('purchase_date', { ascending: false })
        .limit(limit);

      if(error) throw error;
      return data;
  },

  async adminUpdatePurchase(purchaseId: string, updates: { phone?: string, cpf?: string }) {
      // Updates the purchase record AND all associated tickets to maintain consistency
      const { error } = await supabase.from('purchases').update(updates).eq('id', purchaseId);
      if (error) throw error;

      if (updates.cpf) {
          await supabase.from('tickets').update({ owner_cpf: updates.cpf }).eq('purchase_id', purchaseId);
      }
      return { error: null };
  },

  async adminGetRevenueChart() {
      // Mocked aggregation for demo purposes (Supabase doesn't support complex group by without RPC easily)
      // In prod: Create a Database Function for daily revenue
      const { data } = await supabase
        .from('purchases')
        .select('total_value, purchase_date')
        .order('purchase_date', { ascending: true });

      if (!data) return [];

      // Group by date (simple JS aggregation)
      const grouped: Record<string, number> = {};
      data.forEach(p => {
          const date = new Date(p.purchase_date).toLocaleDateString('pt-BR');
          grouped[date] = (grouped[date] || 0) + p.total_value;
      });

      return Object.entries(grouped).map(([date, value]) => ({ date, value }));
  }
};

