import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { HeroCarousel } from './components/HeroCarousel';
import { RaffleCard } from './components/RaffleCard';
import { RaffleDetails } from './components/RaffleDetails';
import { CheckoutModal } from './components/CheckoutModal';
import { SuccessView } from './components/SuccessView';
import { MyTickets } from './components/MyTickets';
import { AdminPanel } from './components/AdminPanel';
import { raffleService } from './services/raffleService';
import { Raffle, RaffleStatus } from './types';
import { Trophy, ShieldCheck, HeartHandshake } from 'lucide-react';

type ViewState = 'home' | 'details' | 'my-tickets' | 'success' | 'admin';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [selectedRaffle, setSelectedRaffle] = useState<Raffle | null>(null);
  const [raffles, setRaffles] = useState<Raffle[]>([]);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [purchaseQty, setPurchaseQty] = useState(1);
  const [purchasedNumbers, setPurchasedNumbers] = useState<number[]>([]);

  useEffect(() => {
    // Basic routing simulation
    if (window.location.pathname === '/adm') {
      setView('admin');
    }

    loadRaffles();
  }, []);

  const loadRaffles = async () => {
    try {
        const data = await raffleService.getAllRaffles();
        setRaffles(data);
    } catch (e) {
        console.error("Failed to load raffles", e);
    }
  };

  const handleRaffleClick = (raffle: Raffle) => {
    setSelectedRaffle(raffle);
    setView('details');
    window.scrollTo(0, 0);
  };

  const handleBuyClick = (qty: number) => {
    setPurchaseQty(qty);
    setIsCheckoutOpen(true);
  };

  const handlePurchaseSuccess = (numbers: number[]) => {
    setIsCheckoutOpen(false);
    setPurchasedNumbers(numbers);
    setView('success');
    window.scrollTo(0, 0);
    loadRaffles(); // Refresh data
  };

  const activeRaffles = raffles.filter(r => r.status === RaffleStatus.ACTIVE);
  const finishedRaffles = raffles.filter(r => r.status === RaffleStatus.FINISHED);

  if (view === 'admin') {
    return <AdminPanel onExit={() => {
        setView('home');
        window.history.pushState({}, '', '/');
    }} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-zinc-950 font-sans selection:bg-yellow-500 selection:text-black">
      <Navbar onNavigate={(v) => {
        setView(v);
        window.scrollTo(0, 0);
      }} />

      <main className="flex-1 pb-20">
        {view === 'home' && (
          <div className="space-y-6 animate-in fade-in duration-500">

            <div className="max-w-6xl mx-auto px-4 mt-4 md:mt-6">
              <HeroCarousel />

              {/* Features - More Compact */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:gap-6 mb-8 mt-6">
                <div className="bg-zinc-900/50 border border-zinc-800 p-4 md:p-6 rounded-xl flex items-center gap-4">
                  <Trophy className="text-yellow-500 w-8 h-8 md:w-10 md:h-10" />
                  <div>
                    <h3 className="font-bold text-white text-sm md:text-base">Prêmios Incríveis</h3>
                    <p className="text-xs md:text-sm text-zinc-400">Carros, motos e eletrônicos</p>
                  </div>
                </div>
                <div className="bg-zinc-900/50 border border-zinc-800 p-4 md:p-6 rounded-xl flex items-center gap-4">
                  <ShieldCheck className="text-yellow-500 w-8 h-8 md:w-10 md:h-10" />
                  <div>
                    <h3 className="font-bold text-white text-sm md:text-base">100% Seguro</h3>
                    <p className="text-xs md:text-sm text-zinc-400">Sorteio pela Loteria Federal</p>
                  </div>
                </div>
                <div className="bg-zinc-900/50 border border-zinc-800 p-4 md:p-6 rounded-xl flex items-center gap-4">
                  <HeartHandshake className="text-yellow-500 w-8 h-8 md:w-10 md:h-10" />
                  <div>
                    <h3 className="font-bold text-white text-sm md:text-base">Baixo Custo</h3>
                    <p className="text-xs md:text-sm text-zinc-400">Chances reais por centavos</p>
                  </div>
                </div>
              </div>

              {/* Active Raffles */}
              <section className="mb-12">
                <div className="flex items-center gap-3 mb-6">
                  <div className="w-1.5 h-6 md:h-8 bg-yellow-500 rounded-full"></div>
                  <h2 className="text-2xl md:text-3xl font-black text-white">Rifas Ativas</h2>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
                  {activeRaffles.map(raffle => (
                    <RaffleCard key={raffle.id} raffle={raffle} onClick={handleRaffleClick} />
                  ))}
                </div>
              </section>

              {/* Finished Raffles */}
              {finishedRaffles.length > 0 && (
                <section>
                  <div className="flex items-center gap-3 mb-6 opacity-75">
                     <div className="w-1.5 h-6 md:h-8 bg-zinc-700 rounded-full"></div>
                    <h2 className="text-2xl md:text-3xl font-black text-white">Rifas Finalizadas</h2>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8 opacity-75 grayscale hover:grayscale-0 transition-all duration-500">
                    {finishedRaffles.map(raffle => (
                      <RaffleCard key={raffle.id} raffle={raffle} onClick={handleRaffleClick} />
                    ))}
                  </div>
                </section>
              )}
            </div>
          </div>
        )}

        {view === 'details' && selectedRaffle && (
          <div className="max-w-6xl mx-auto px-4 py-8">
            <RaffleDetails 
              raffle={selectedRaffle} 
              onBack={() => setView('home')}
              onBuy={handleBuyClick}
            />
          </div>
        )}

        {view === 'my-tickets' && (
          <div className="max-w-6xl mx-auto px-4 py-8">
            <div className="mb-6">
                 <button 
                  onClick={() => setView('home')}
                  className="flex items-center gap-2 text-zinc-400 hover:text-white transition-colors"
                >
                  <ArrowBackIcon /> Voltar para Home
                </button>
            </div>
            <MyTickets />
          </div>
        )}

        {view === 'success' && selectedRaffle && (
          <div className="max-w-4xl mx-auto px-4 py-8">
            <SuccessView 
              raffleName={selectedRaffle.name} 
              numbers={purchasedNumbers}
              onHome={() => setView('home')}
              onMyTickets={() => setView('my-tickets')}
            />
          </div>
        )}
      </main>

      <footer className="bg-black border-t border-zinc-900 py-8 text-center text-zinc-600 text-sm">
        <p className="mb-2">© 2024 BRABO PREMIAÇÕES. Todos os direitos reservados.</p>
        <p>Desenvolvido para demonstração.</p>
      </footer>

      {isCheckoutOpen && selectedRaffle && (
        <CheckoutModal 
          raffle={selectedRaffle} 
          quantity={purchaseQty} 
          onClose={() => setIsCheckoutOpen(false)}
          onSuccess={handlePurchaseSuccess}
        />
      )}
    </div>
  );
};

const ArrowBackIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
);

export default App;

