import React from 'react';
import { Raffle, RaffleStatus } from '../types';
import { CheckCircle2, AlertCircle } from 'lucide-react';

interface RaffleCardProps {
  raffle: Raffle;
  onClick: (raffle: Raffle) => void;
}

export const RaffleCard: React.FC<RaffleCardProps> = ({ raffle, onClick }) => {
  // Use the larger value between real sales and the manual override
  const displaySold = Math.max(raffle.soldNumbers, raffle.fakeSoldNumbers || 0);
  const percentage = Math.min(100, Math.floor((displaySold / raffle.totalNumbers) * 100));
  const isFinished = raffle.status === RaffleStatus.FINISHED;

  return (
    <div 
      onClick={() => onClick(raffle)}
      className={`group relative bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden hover:border-yellow-600/50 transition-all cursor-pointer hover:shadow-xl hover:shadow-yellow-900/10 flex flex-col h-full`}
    >
      {/* Image Container - 1350x1080 Aspect Ratio */}
      <div className="relative w-full aspect-[1350/1080] overflow-hidden bg-zinc-950/50">
        <img 
          src={raffle.imageUrl} 
          alt={raffle.name} 
          className="w-full h-full object-contain group-hover:scale-105 transition-transform duration-500"
        />
        {isFinished ? (
          <div className="absolute inset-0 flex items-center justify-center backdrop-blur-[1px]">
            <span className="bg-red-600 text-white px-4 py-1 rounded-full text-sm font-bold uppercase tracking-wider flex items-center gap-2 shadow-lg">
              <CheckCircle2 size={16} /> Finalizada
            </span>
          </div>
        ) : (
          <div className="absolute top-2 right-2">
             <span className="bg-green-600/90 text-white px-3 py-1 rounded-full text-xs font-bold shadow-lg animate-pulse">
               CORRE
             </span>
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-5 flex-1 flex flex-col pt-2">
        <h3 className="text-xl font-bold text-white mb-2 line-clamp-1">{raffle.name}</h3>
        <p className="text-zinc-400 text-sm mb-4 line-clamp-2">{raffle.description}</p>

        <div className="mt-auto">
          {isFinished ? (
            <div className="text-center py-2 bg-zinc-800/50 rounded-lg">
              <p className="text-zinc-500 font-medium">Sorteio realizado</p>
            </div>
          ) : (
            <>
              <div className="flex justify-between text-xs font-semibold text-zinc-400 mb-1">
                <span>{percentage}% vendido</span>
                <span className="text-yellow-500">Restam {100 - percentage}%</span>
              </div>
              <div className="w-full h-2.5 bg-zinc-800 rounded-full overflow-hidden mb-4">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-600 to-yellow-400 rounded-full transition-all duration-1000"
                  style={{ width: `${percentage}%` }}
                ></div>
              </div>

              <button className="w-full py-3 bg-yellow-600 hover:bg-yellow-500 text-black font-bold rounded-lg transition-colors flex items-center justify-center gap-2">
                <div className="text-sm">POR APENAS</div>
                <div className="text-lg">R$ {raffle.pricePerNumber.toFixed(2).replace('.', ',')}</div>
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Raffle, RaffleStatus } from '../types';
import { ArrowLeft, Minus, Plus, ShoppingCart, Award } from 'lucide-react';

interface RaffleDetailsProps {
  raffle: Raffle;
  onBack: () => void;
  onBuy: (qty: number) => void;
}

export const RaffleDetails: React.FC<RaffleDetailsProps> = ({ raffle, onBack, onBuy }) => {
  const minPurchase = raffle.minPurchase || 1;
  const [quantity, setQuantity] = useState(minPurchase);

  // Use max between real and fake
  const displaySold = Math.max(raffle.soldNumbers, raffle.fakeSoldNumbers || 0);
  const percentage = Math.floor((displaySold / raffle.totalNumbers) * 100);

  const handleQuantityChange = (val: string) => {
    const num = parseInt(val);
    if (!isNaN(num) && num >= minPurchase) setQuantity(num);
  };

  const increment = () => setQuantity(prev => prev + 1);
  const decrement = () => setQuantity(prev => (prev > minPurchase ? prev - 1 : minPurchase));

  // Dynamic quick options based on min purchase
  const quickOptions = [minPurchase, minPurchase + 5, minPurchase + 10, minPurchase + 50, minPurchase + 100];

  return (
    <div className="animate-in slide-in-from-right-8 fade-in duration-300">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-zinc-400 hover:text-white mb-6 transition-colors"
      >
        <ArrowLeft size={20} />
        Voltar para Home
      </button>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Left: Image - 1350x1080 Aspect Ratio */}
        <div className="space-y-4">
          <div className="w-full aspect-[1350/1080] bg-zinc-900/50 rounded-xl overflow-hidden border border-zinc-800/50">
            <img 
                src={raffle.imageUrl} 
                alt={raffle.name} 
                className="w-full h-full object-contain" 
            />
          </div>

          <div className="bg-zinc-900 rounded-xl p-4 border border-zinc-800">
            <h3 className="text-white font-bold flex items-center gap-2 mb-2">
              <Award className="text-yellow-500" />
              Descrição do Prêmio
            </h3>
            <p className="text-zinc-400 text-sm leading-relaxed whitespace-pre-line">
              {raffle.fullDescription}
            </p>
          </div>
        </div>

        {/* Right: Info & Purchase */}
        <div className="flex flex-col">
          <h1 className="text-3xl font-black text-white mb-2">{raffle.name}</h1>
          <p className="text-zinc-400 mb-6">{raffle.description}</p>

          {/* Progress */}
          <div className="bg-zinc-900 rounded-xl p-5 border border-zinc-800 mb-6">
            <div className="flex justify-between text-sm font-medium mb-2">
              <span className="text-white">Progresso da Ação</span>
              <span className="text-yellow-500 font-bold">{percentage}%</span>
            </div>
            <div className="w-full h-3 bg-black rounded-full overflow-hidden">
              <div 
                className="h-full bg-gradient-to-r from-yellow-600 to-yellow-400 rounded-full transition-all duration-1000"
                style={{ width: `${percentage}%` }}
              ></div>
            </div>
            <p className="text-xs text-zinc-500 mt-2 text-right">
              {displaySold.toLocaleString()} de {raffle.totalNumbers.toLocaleString()} cotas vendidas
            </p>
          </div>

          {raffle.status === RaffleStatus.ACTIVE ? (
            <div className="bg-zinc-900 rounded-xl p-6 border border-yellow-600/30 shadow-lg shadow-yellow-900/10 flex-1 flex flex-col">
              <div className="text-center mb-6">
                <span className="text-zinc-400 text-sm uppercase tracking-wider">Por apenas</span>
                <div className="text-4xl font-black text-white mt-1">
                  R$ {raffle.pricePerNumber.toFixed(2).replace('.', ',')}
                </div>
                {minPurchase > 1 && (
                     <span className="text-yellow-600 text-xs font-bold bg-yellow-900/20 px-2 py-1 rounded mt-2 inline-block">Mínimo: {minPurchase} cotas</span>
                )}
              </div>

              {/* Quantity Selector */}
              <div className="mb-6">
                <label className="block text-sm text-zinc-400 mb-2 font-medium">Quantas cotas você quer?</label>
                <div className="flex items-center gap-3 mb-3">
                  <button onClick={decrement} className="w-12 h-12 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-white transition-colors disabled:opacity-50" disabled={quantity <= minPurchase}>
                    <Minus size={20} />
                  </button>
                  <input 
                    type="number" 
                    value={quantity}
                    onChange={(e) => handleQuantityChange(e.target.value)}
                    className="flex-1 bg-black border border-zinc-700 rounded-lg h-12 text-center text-xl font-bold text-white focus:border-yellow-500 outline-none"
                  />
                  <button onClick={increment} className="w-12 h-12 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-white transition-colors">
                    <Plus size={20} />
                  </button>
                </div>

                {/* Quick select */}
                <div className="flex flex-wrap gap-2">
                  {quickOptions.map(opt => (
                    <button
                      key={opt}
                      onClick={() => setQuantity(opt)}
                      className={`px-3 py-1 rounded-full text-xs font-bold border transition-all ${
                        quantity === opt 
                        ? 'bg-yellow-600 border-yellow-600 text-black' 
                        : 'bg-transparent border-zinc-700 text-zinc-400 hover:border-yellow-500 hover:text-yellow-500'
                      }`}
                    >
                      {opt} cotas
                    </button>
                  ))}
                </div>
              </div>

              <div className="mt-auto pt-6 border-t border-zinc-800">
                <div className="flex justify-between items-end mb-4">
                  <span className="text-zinc-400">Total</span>
                  <span className="text-3xl font-bold text-yellow-500">
                    R$ {(quantity * raffle.pricePerNumber).toFixed(2).replace('.', ',')}
                  </span>
                </div>
                <button 
                  onClick={() => onBuy(quantity)}
                  className="w-full py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl text-lg flex items-center justify-center gap-2 shadow-lg shadow-green-900/30 transition-all hover:scale-[1.02]"
                >
                  <ShoppingCart size={24} />
                  Comprar {quantity} Cotas
                </button>
              </div>
            </div>
          ) : (
            <div className="bg-zinc-800 rounded-xl p-8 flex flex-col items-center justify-center text-center h-full opacity-75">
              <h2 className="text-2xl font-bold text-white mb-2">Ação Finalizada</h2>
              <p className="text-zinc-400">Todas as cotas foram vendidas ou o sorteio já foi realizado.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export enum RaffleStatus {
  ACTIVE = 'ACTIVE',
  FINISHED = 'FINISHED'
}

