  raffleId: string;
  ticketNumber: number;
  prizeDescription: string;
  isActive: boolean;
  isSold: boolean;
  winnerName?: string;
}

export interface Purchase {
  id: string;
  cpf: string;
  phone: string;
  raffleId: string;
  raffleName?: string; // For admin display
  quantity: number;
  totalValue: number;
  purchaseDate: string;
  ticketNumbers: number[]; 
}

export interface Banner {
  id: string;
  image_url: string;
  active: boolean;
}

// Helper type for Supabase raw response if needed
export interface DB_Purchase {
  id: string;
  raffle_id: string;
  cpf: string;
  phone: string;
  quantity: number;
  total_value: number;
  purchase_date: string;
}

export interface PurchaseResult {
  success: boolean; 
  numbers: number[]; 
  message?: string;
  wonPrizes?: { number: number; prize: string }[]; // New field for instant wins
}

import { supabase } from './supabaseClient';
import { Raffle, RaffleStatus, Purchase, Banner, WinningTicket, PurchaseResult } from '../types';

export const raffleService = {
  // --- PUBLIC METHODS ---

  async getBanners(): Promise<string[]> {
    const { data, error } = await supabase
      .from('banners')
      .select('image_url')
      .eq('active', true)
      .order('created_at', { ascending: false });

    if (error || !data) {
      return []; 
    }
    return data.map(b => b.image_url);
  },

  async getAllRaffles(): Promise<Raffle[]> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw error;

    const rafflesWithCount = await Promise.all(data.map(async (r: any) => {
        const { count } = await supabase
            .from('tickets')
            .select('*', { count: 'exact', head: true })
            .eq('raffle_id', r.id);

        return {
            id: r.id,
            name: r.name,
            description: r.description,
            fullDescription: r.full_description,
            imageUrl: r.image_url,
            totalNumbers: r.total_numbers,
            soldNumbers: count || 0,
            fakeSoldNumbers: r.fake_sold_numbers || 0,
            pricePerNumber: r.price_per_number,
            minPurchase: r.min_purchase || 1,
            status: r.status as RaffleStatus,
            winnerNumber: r.winner_number,
            winnerName: r.winner_name
        };
    }));

    return rafflesWithCount;
  },

  async getRaffleById(id: string): Promise<Raffle | undefined> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .eq('id', id)
      .single();

    if (error || !data) return undefined;

    const { count } = await supabase
        .from('tickets')
        .select('*', { count: 'exact', head: true })
        .eq('raffle_id', id);

    return {
        id: data.id,
        name: data.name,
        description: data.description,
        fullDescription: data.full_description,
        imageUrl: data.image_url,
        totalNumbers: data.total_numbers,
        soldNumbers: count || 0,
        fakeSoldNumbers: data.fake_sold_numbers || 0,
        pricePerNumber: data.price_per_number,
        minPurchase: data.min_purchase || 1,
        status: data.status as RaffleStatus,
        winnerNumber: data.winner_number,
        winnerName: data.winner_name
    };
  },

  async purchaseTickets(
    raffleId: string,
    quantity: number,
    cpf: string,
    phone: string
  ): Promise<PurchaseResult> {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    const raffle = await this.getRaffleById(raffleId);
    if (!raffle) return { success: false, numbers: [], message: 'Rifa não encontrada.' };

    if (quantity < (raffle.minPurchase || 1)) {
        return { success: false, numbers: [], message: `A compra mínima é de ${raffle.minPurchase} cotas.` };
    }

    if (raffle.soldNumbers + quantity > raffle.totalNumbers) {
      return { success: false, numbers: [], message: 'Quantidade indisponível.' };
    }

    // --- LOGIC CHANGE: Winning Tickets Check ---
    // Fetch blocked tickets (winning tickets that are INACTIVE)
    const { data: blockedTickets } = await supabase
        .from('winning_tickets')
        .select('ticket_number')
        .eq('raffle_id', raffleId)
        .eq('is_active', false) // These cannot be bought yet
        .eq('is_sold', false);

    const blockedSet = new Set(blockedTickets?.map(t => t.ticket_number) || []);

    const generatedNumbers: number[] = [];
    let attempts = 0;
    const maxAttempts = quantity * 10; // Increased attempts due to blocking logic

    while (generatedNumbers.length < quantity && attempts < maxAttempts) {
        attempts++;
        // 1. Random Generation (Not sequential)
        const candidate = Math.floor(Math.random() * raffle.totalNumbers);

        // 2. Check if already picked in this batch
        if (generatedNumbers.includes(candidate)) continue;

        // 3. Check if it's a BLOCKED winning ticket
        if (blockedSet.has(candidate)) continue; // SKIP THIS NUMBER, it's reserved and locked

        // 4. Check if already sold in DB
        const { data } = await supabase
            .from('tickets')
            .select('number')
            .eq('raffle_id', raffleId)
            .eq('number', candidate)
            .single();

        if (!data) {
            generatedNumbers.push(candidate);
        }
    }

    if (generatedNumbers.length < quantity) {
        return { success: false, numbers: [], message: 'Erro ao gerar números (conflito de disponibilidade). Tente novamente.' };
    }
    generatedNumbers.sort((a, b) => a - b);

    // Create Purchase Record
    const { data: purchaseData, error: purchaseError } = await supabase
        .from('purchases')
        .insert({
            raffle_id: raffleId,
            cpf: cleanCpf,
            phone: cleanPhone,
            quantity: quantity,
            total_value: quantity * raffle.pricePerNumber
        })
        .select()
        .single();

    if (purchaseError || !purchaseData) {
        console.error(purchaseError);
        return { success: false, numbers: [], message: 'Erro ao registrar compra.' };
    }

    // Create Tickets
    const ticketsPayload = generatedNumbers.map(num => ({
        raffle_id: raffleId,
        purchase_id: purchaseData.id,
        number: num,
        owner_cpf: cleanCpf
    }));

    const { error: ticketsError } = await supabase.from('tickets').insert(ticketsPayload);

    if (ticketsError) {
        console.error(ticketsError);
        return { success: false, numbers: [], message: 'Erro crítico ao gerar bilhetes.' };
    }

    // --- CHECK FOR WINNERS ---
    // Now we check if any of the purchased numbers correspond to an ACTIVE winning ticket
    const { data: wonTickets } = await supabase
        .from('winning_tickets')
        .select('ticket_number, prize_description, id')
        .eq('raffle_id', raffleId)
        .eq('is_active', true) // Must be active
        .eq('is_sold', false)
        .in('ticket_number', generatedNumbers);

    const wonPrizes: { number: number; prize: string }[] = [];

    if (wonTickets && wonTickets.length > 0) {
        for (const won of wonTickets) {
            // Update the winning ticket as SOLD
            await supabase.from('winning_tickets').update({
                is_sold: true,
                purchase_id: purchaseData.id,
                winner_cpf: cleanCpf,
                winner_name: 'Comprador (Aguardando)' 
            }).eq('id', won.id);

            wonPrizes.push({ number: won.ticket_number, prize: won.prize_description });
        }
    }

    return { success: true, numbers: generatedNumbers, wonPrizes };
  },

  async getMyTickets(cpf: string): Promise<Purchase[]> {
    const cleanCpf = cpf.replace(/\D/g, '');

    const { data: purchases, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .eq('cpf', cleanCpf)
        .order('purchase_date', { ascending: false });

    if (error) return [];

    const fullPurchases = await Promise.all(purchases.map(async (p: any) => {
        const { data: tickets } = await supabase
            .from('tickets')
            .select('number')
            .eq('purchase_id', p.id);

        return {
            id: p.id,
            cpf: p.cpf,
            phone: p.phone,
            raffleId: p.raffle_id,
            raffleName: p.raffles?.name,
            quantity: p.quantity,
            totalValue: p.total_value,
            purchaseDate: p.purchase_date,
            ticketNumbers: tickets?.map((t: any) => t.number).sort((a: number, b: number) => a - b) || []
        };
    }));

    return fullPurchases;
  },

  // --- ADMIN METHODS ---

  async adminGetWinningTickets(raffleId: string): Promise<WinningTicket[]> {
      const { data } = await supabase
        .from('winning_tickets')
        .select('*')
        .eq('raffle_id', raffleId)
        .order('ticket_number', { ascending: true });

      if (!data) return [];

      return data.map(t => ({
          id: t.id,
          raffleId: t.raffle_id,
          ticketNumber: t.ticket_number,
          prizeDescription: t.prize_description,
          isActive: t.is_active,
          isSold: t.is_sold,
          winnerName: t.winner_name
      }));
  },

  async adminCreateWinningTicket(raffleId: string, number: number, prize: string) {
      const { error } = await supabase.from('winning_tickets').insert({
          raffle_id: raffleId,
          ticket_number: number,
          prize_description: prize,
          is_active: false // Start inactive (locked) by default
      });
      if (error) throw error;
  },

  async adminToggleWinningTicket(id: string, isActive: boolean) {
      const { error } = await supabase.from('winning_tickets').update({ is_active: isActive }).eq('id', id);
      if (error) throw error;
  },

  async adminDeleteWinningTicket(id: string) {
      const { error } = await supabase.from('winning_tickets').delete().eq('id', id);
      if (error) throw error;
  },

  async adminGetStats() {
      const { data: purchases } = await supabase.from('purchases').select('total_value');
      const totalRevenue = purchases?.reduce((acc, curr) => acc + (curr.total_value || 0), 0) || 0;

      const { count: activeRaffles } = await supabase.from('raffles').select('*', { count: 'exact', head: true }).eq('status', 'ACTIVE');
      const { count: totalTickets } = await supabase.from('tickets').select('*', { count: 'exact', head: true });

      const avgTicket = purchases && purchases.length > 0 ? totalRevenue / purchases.length : 0;

      return { totalRevenue, activeRaffles, totalTickets, avgTicket };
  },

  // Banner Management
  async adminGetBanners() {
      const { data } = await supabase.from('banners').select('*').order('created_at', { ascending: false });
      return data || [];
  },

  async adminCreateBanner(imageUrl: string) {
      const { error } = await supabase.from('banners').insert({ image_url: imageUrl, active: true });
      if (error) throw error;
  },

  async adminDeleteBanner(id: string) {
      const { error } = await supabase.from('banners').delete().eq('id', id);
      if (error) throw error;
  },

  // Raffle Management
  async createRaffle(data: Partial<Raffle>) {
      const payload = {
          name: data.name,
          description: data.description,
          full_description: data.fullDescription,
          image_url: data.imageUrl,
          total_numbers: data.totalNumbers,
          price_per_number: data.pricePerNumber,
          min_purchase: data.minPurchase || 1,
          fake_sold_numbers: data.fakeSoldNumbers || 0,
          status: 'ACTIVE'
      };

      const { data: created, error } = await supabase.from('raffles').insert(payload).select().single();

      if (error) {
          console.error("Erro ao criar rifa:", error);
          throw error;
      }
      return created;
  },

  async updateRaffle(id: string, updates: any) {
     const { error } = await supabase.from('raffles').update(updates).eq('id', id);
     if (error) {
         console.error("Erro ao atualizar rifa:", error);
         throw error;
     }
  },

  // Ticket Management (unchanged)
  async getTicketOwner(raffleId: string, number: number) {
      return await supabase
        .from('tickets')
        .select('*, purchases(phone, cpf, purchase_date)')
        .eq('raffle_id', raffleId)
        .eq('number', number)
        .single();
  },

  async adminUpdateTicketOwner(ticketId: string, newCpf: string) {
      const { error } = await supabase.from('tickets').update({ owner_cpf: newCpf }).eq('id', ticketId);
      if (error) throw error;
  },

  // Purchases Management (unchanged)
  async adminGetAllPurchases(limit = 50) {
      const { data, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .order('purchase_date', { ascending: false })
        .limit(limit);

      if(error) throw error;
      return data;
  },

  async adminUpdatePurchase(purchaseId: string, updates: { phone?: string, cpf?: string }) {
      const { error } = await supabase.from('purchases').update(updates).eq('id', purchaseId);
      if (error) throw error;

      if (updates.cpf) {
          const { error: ticketError } = await supabase.from('tickets').update({ owner_cpf: updates.cpf }).eq('purchase_id', purchaseId);
          if (ticketError) throw ticketError;
      }
      return { error: null };
  },

  async adminGetRevenueChart() {
      const { data } = await supabase
        .from('purchases')
        .select('total_value, purchase_date')
        .order('purchase_date', { ascending: true });

      if (!data) return [];

      const grouped: Record<string, number> = {};
      data.forEach(p => {
          const date = new Date(p.purchase_date).toLocaleDateString('pt-BR');
          grouped[date] = (grouped[date] || 0) + p.total_value;
      });

      return Object.entries(grouped).map(([date, value]) => ({ date, value }));
  }
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { raffleService } from '../services/raffleService';
import { Raffle, Purchase, Banner, WinningTicket } from '../types';
import { 
  LayoutDashboard, 
  Plus, 
  Edit, 
  Trash2, 
  Ticket, 
  DollarSign, 
  Users, 
  LogOut, 
  Save, 
  X,
  Search,
  Trophy,
  Loader2,
  Lock,
  Image as ImageIcon,
  TrendingUp,
  ShoppingBag,
  RefreshCw,
  AlertTriangle,
  Unlock,
  Gift
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer } from 'recharts';

export const AdminPanel: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  const [session, setSession] = useState<any>(null);
  const [loadingSession, setLoadingSession] = useState(true);

  // Login State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [loggingIn, setLoggingIn] = useState(false);

  // Tabs
  const [activeTab, setActiveTab] = useState<'dashboard' | 'raffles' | 'tickets' | 'sales' | 'site'>('dashboard');

  // Data
  const [stats, setStats] = useState({ totalRevenue: 0, activeRaffles: 0, totalTickets: 0, avgTicket: 0 });
  const [chartData, setChartData] = useState<any[]>([]);
  const [raffles, setRaffles] = useState<Raffle[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  // Raffle Form
  const [isEditing, setIsEditing] = useState<Raffle | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [formData, setFormData] = useState<any>({});
  const [savingRaffle, setSavingRaffle] = useState(false);
  const [manualProgressPercent, setManualProgressPercent] = useState<number | string>('');

  // Winning Tickets State
  const [winningTickets, setWinningTickets] = useState<WinningTicket[]>([]);
  const [newWinningTicket, setNewWinningTicket] = useState({ number: '', prize: '' });

  // Ticket Manager
  const [searchTicket, setSearchTicket] = useState({ raffleId: '', number: '' });
  const [foundTicket, setFoundTicket] = useState<any>(null);
  const [newOwnerCpf, setNewOwnerCpf] = useState('');

  // Sales Manager
  const [purchases, setPurchases] = useState<any[]>([]);
  const [editPurchase, setEditPurchase] = useState<any>(null);

  // Site Manager (Banners)
  const [banners, setBanners] = useState<any[]>([]);
  const [newBannerUrl, setNewBannerUrl] = useState('');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoadingSession(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session) {
      loadDashboard();
    }
  }, [session]);

  const loadDashboard = async () => {
    setLoadingData(true);
    try {
        const s = await raffleService.adminGetStats();
        // @ts-ignore
        setStats(s);
        const r = await raffleService.getAllRaffles();
        setRaffles(r);
        const c = await raffleService.adminGetRevenueChart();
        setChartData(c);
    } catch (error) {
        console.error("Erro ao carregar dashboard", error);
    } finally {
        setLoadingData(false);
    }
  };

  // --- TAB LOADERS ---
  useEffect(() => {
      if(!session) return;
      if (activeTab === 'sales') loadPurchases();
      if (activeTab === 'site') loadBanners();
  }, [activeTab]);

  const loadPurchases = async () => {
      setLoadingData(true);
      try {
          const data = await raffleService.adminGetAllPurchases(100);
          setPurchases(data || []);
      } catch(e) { console.error(e); } 
      finally { setLoadingData(false); }
  };

  const loadBanners = async () => {
      try {
          const data = await raffleService.adminGetBanners();
          setBanners(data);
      } catch(e) { console.error(e); }
  };

  const loadWinningTickets = async (raffleId: string) => {
      try {
          const tickets = await raffleService.adminGetWinningTickets(raffleId);
          setWinningTickets(tickets);
      } catch (e) { console.error(e); }
  };

  // --- HELPERS ---
  const handleOpenEdit = (raffle: Raffle) => {
      setIsEditing(raffle);
      setIsCreating(false);
      setFormData(raffle);
      loadWinningTickets(raffle.id);

      // Calculate current visible percentage
      const currentSold = Math.max(raffle.soldNumbers, raffle.fakeSoldNumbers || 0);
      const percent = Math.floor((currentSold / raffle.totalNumbers) * 100);
      setManualProgressPercent(percent);
  };

  const handleOpenCreate = () => {
      setIsCreating(true);
      setIsEditing(null);
      setWinningTickets([]);
      setFormData({ totalNumbers: 1000, pricePerNumber: 0.99, minPurchase: 1 });
      setManualProgressPercent(0);
  };

  // --- ACTIONS ---

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoggingIn(true);
    setLoginError('');
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setLoginError('Email ou senha inválidos.');
    setLoggingIn(false);
  };

  const handleSaveRaffle = async (e: React.FormEvent) => {
      e.preventDefault();
      setSavingRaffle(true);
      try {
          // Calculate fake sold numbers based on percentage input
          const percent = parseFloat(manualProgressPercent.toString()) || 0;
          const total = parseInt(formData.totalNumbers);
          const fakeSold = Math.floor((percent / 100) * total);

          const payload = {
            fakeSoldNumbers: fakeSold,
            ...formData
          };

          if (isCreating) {
              await raffleService.createRaffle(payload);
          } else if (isEditing) {
              await raffleService.updateRaffle(isEditing.id, {
                  name: formData.name,
                  description: formData.description,
                  full_description: formData.fullDescription,
                  image_url: formData.imageUrl,
                  price_per_number: formData.pricePerNumber,
                  min_purchase: formData.minPurchase,
                  status: formData.status,
                  fake_sold_numbers: fakeSold,
                  winner_number: formData.winnerNumber || null,
                  winner_name: formData.winnerName || null
              });
          }
          alert('Rifa salva com sucesso!');
          setIsCreating(false);
          setIsEditing(null);
          setFormData({});
          loadDashboard(); // Refresh
      } catch (err: any) {
          console.error(err);
          if (err.message && err.message.includes("Could not find the 'min_purchase' column")) {
              alert("⚠️ Erro: Coluna 'min_purchase' faltando.");
          } else if (err.message && err.message.includes("Could not find the 'fake_sold_numbers' column")) {
             alert("⚠️ ERRO: Coluna 'fake_sold_numbers' faltando.");
          } else {
              alert(`Erro ao salvar rifa: ${err.message || 'Erro desconhecido'}.`);
          }
      } finally {
          setSavingRaffle(false);
      }
  };

  const handleAddWinningTicket = async () => {
      if (!isEditing) return alert('Salve a rifa antes de adicionar bilhetes premiados.');
      if (!newWinningTicket.number || !newWinningTicket.prize) return alert('Preencha o número e o prêmio.');

      try {
          await raffleService.adminCreateWinningTicket(isEditing.id, parseInt(newWinningTicket.number), newWinningTicket.prize);
          setNewWinningTicket({ number: '', prize: '' });
          loadWinningTickets(isEditing.id);
      } catch(e: any) {
          alert('Erro ao criar bilhete premiado: ' + e.message);
      }
  };

  const handleToggleWinningTicket = async (id: string, currentStatus: boolean) => {
      try {
          await raffleService.adminToggleWinningTicket(id, !currentStatus);
          loadWinningTickets(isEditing!.id);
      } catch(e: any) {
          alert('Erro: ' + e.message);
      }
  };

  const handleDeleteWinningTicket = async (id: string) => {
      if(!confirm('Remover este bilhete premiado?')) return;
      try {
          await raffleService.adminDeleteWinningTicket(id);
          loadWinningTickets(isEditing!.id);
      } catch(e: any) {
          alert('Erro: ' + e.message);
      }
  };

  const handleDeleteRaffle = async (id: string) => {
      if(!confirm('ATENÇÃO: Deletar uma rifa apaga todo histórico de vendas dela. Confirmar?')) return;
      const { error } = await supabase.from('raffles').delete().eq('id', id);
      if (error) alert('Erro ao deletar: ' + error.message);
      else loadDashboard();
  };

  const handleSearchTicket = async (e: React.FormEvent) => {
      e.preventDefault();
      setFoundTicket(null);
      const { data, error } = await raffleService.getTicketOwner(searchTicket.raffleId, parseInt(searchTicket.number));
      if(error || !data) setFoundTicket({ error: 'Bilhete não encontrado.' });
      else setFoundTicket(data);
  };

  const handleUpdateTicketOwner = async () => {
      if (!foundTicket || !foundTicket.id) return;
      if (!newOwnerCpf || newOwnerCpf.length < 11) return alert('CPF inválido');

      try {
          await raffleService.adminUpdateTicketOwner(foundTicket.id, newOwnerCpf);
          alert('Dono do bilhete atualizado com sucesso!');
          setFoundTicket(prev => ({...prev, owner_cpf: newOwnerCpf}));
          setNewOwnerCpf('');
      } catch(e: any) {
          alert('Erro ao atualizar dono: ' + e.message);
      }
  };

  const handleUpdatePurchase = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!editPurchase) return;
      try {
          await raffleService.adminUpdatePurchase(editPurchase.id, { 
              phone: editPurchase.phone, 
              cpf: editPurchase.cpf 
          });
          setEditPurchase(null);
          loadPurchases();
          alert('Dados da compra atualizados.');
      } catch(e: any) {
          alert('Erro ao atualizar compra: ' + e.message);
      }
  };

  const handleAddBanner = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!newBannerUrl) return;
      try {
          await raffleService.adminCreateBanner(newBannerUrl);
          setNewBannerUrl('');
          loadBanners();
      } catch(e: any) {
          alert('Erro ao adicionar banner: ' + e.message);
      }
  };

  const handleDeleteBanner = async (id: string) => {
      if(!confirm('Remover banner?')) return;
      try {
          await raffleService.adminDeleteBanner(id);
          loadBanners();
      } catch(e: any) {
          alert('Erro ao remover banner: ' + e.message);
      }
  };


  // --- VIEW ---

  if (loadingSession) return <div className="min-h-screen bg-zinc-950 flex items-center justify-center text-white"><Loader2 className="animate-spin" /></div>;

  if (!session) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-zinc-950 p-4">
        <form onSubmit={handleLogin} className="bg-zinc-900 p-8 rounded-2xl border border-zinc-800 w-full max-w-md shadow-2xl">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-yellow-900/20 rounded-full"><Lock className="w-8 h-8 text-yellow-500" /></div>
          </div>
          <h2 className="text-2xl font-bold text-white mb-2 text-center">Admin Pro</h2>
          {loginError && <div className="bg-red-900/30 border border-red-800 text-red-200 p-3 rounded mb-4 text-sm text-center">{loginError}</div>}
