import { supabase } from './supabaseClient';
import { Raffle, RaffleStatus, Purchase, Banner, WinningTicket, PurchaseResult } from '../types';

export const raffleService = {
  // --- PUBLIC METHODS ---

  async getBanners(): Promise<string[]> {
    const { data, error } = await supabase
      .from('banners')
      .select('image_url')
      .eq('active', true)
      .order('created_at', { ascending: false });

    if (error || !data) {
      return []; 
    }
    return data.map(b => b.image_url);
  },

  async getAllRaffles(): Promise<Raffle[]> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw error;

    const rafflesWithCount = await Promise.all(data.map(async (r: any) => {
        const { count } = await supabase
            .from('tickets')
            .select('*', { count: 'exact', head: true })
            .eq('raffle_id', r.id);

        return {
            id: r.id,
            name: r.name,
            description: r.description,
            fullDescription: r.full_description,
            imageUrl: r.image_url,
            totalNumbers: r.total_numbers,
            soldNumbers: count || 0,
            fakeSoldNumbers: r.fake_sold_numbers || 0,
            pricePerNumber: r.price_per_number,
            minPurchase: r.min_purchase || 1,
            status: r.status as RaffleStatus,
            winnerNumber: r.winner_number,
            winnerName: r.winner_name
        };
    }));

    return rafflesWithCount;
  },

  async getRaffleById(id: string): Promise<Raffle | undefined> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .eq('id', id)
      .single();

    if (error || !data) return undefined;

    const { count } = await supabase
        .from('tickets')
        .select('*', { count: 'exact', head: true })
        .eq('raffle_id', id);

    return {
        id: data.id,
        name: data.name,
        description: data.description,
        fullDescription: data.full_description,
        imageUrl: data.image_url,
        totalNumbers: data.total_numbers,
        soldNumbers: count || 0,
        fakeSoldNumbers: data.fake_sold_numbers || 0,
        pricePerNumber: data.price_per_number,
        minPurchase: data.min_purchase || 1,
        status: data.status as RaffleStatus,
        winnerNumber: data.winner_number,
        winnerName: data.winner_name
    };
  },

  // Busca os bilhetes premiados para exibir na página da rifa
  // Retorna tanto os disponíveis quanto os vendidos (com nome)
  async getPublicWinningTickets(raffleId: string): Promise<WinningTicket[]> {
      const { data, error } = await supabase
        .from('winning_tickets')
        .select('id, ticket_number, prize_description, is_sold, winner_name, is_active, raffle_id')
        .eq('raffle_id', raffleId)
        .eq('is_active', true) // Apenas os ativos (liberados pelo admin) aparecem na vitrine
        .order('ticket_number', { ascending: true });

      if (error || !data) return [];

      return data.map(t => ({
          id: t.id,
          raffleId: t.raffle_id,
          ticketNumber: t.ticket_number,
          prizeDescription: t.prize_description,
          isActive: t.is_active,
          isSold: t.is_sold,
          winnerName: t.winner_name
      }));
  },

  async purchaseTickets(
    raffleId: string,
    quantity: number,
    name: string,
    cpf: string,
    phone: string
  ): Promise<PurchaseResult> {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    const raffle = await this.getRaffleById(raffleId);
    if (!raffle) return { success: false, numbers: [], message: 'Rifa não encontrada.' };

    if (quantity < (raffle.minPurchase || 1)) {
        return { success: false, numbers: [], message: `A compra mínima é de ${raffle.minPurchase} cotas.` };
    }

    if (raffle.soldNumbers + quantity > raffle.totalNumbers) {
      return { success: false, numbers: [], message: 'Quantidade indisponível.' };
    }

    // --- LOGIC CHANGE: Winning Tickets Check ---
    // Fetch blocked tickets (winning tickets that are INACTIVE)
    const { data: blockedTickets } = await supabase
        .from('winning_tickets')
        .select('ticket_number')
        .eq('raffle_id', raffleId)
        .eq('is_active', false) // These cannot be bought yet
        .eq('is_sold', false);

    const blockedSet = new Set(blockedTickets?.map(t => t.ticket_number) || []);

    const generatedNumbers: number[] = [];
    let attempts = 0;
    const maxAttempts = quantity * 15; 

    while (generatedNumbers.length < quantity && attempts < maxAttempts) {
        attempts++;
        const candidate = Math.floor(Math.random() * raffle.totalNumbers);

        if (generatedNumbers.includes(candidate)) continue;
        if (blockedSet.has(candidate)) continue; // SKIP LOCKED WINNING TICKETS

        const { data } = await supabase
            .from('tickets')
            .select('number')
            .eq('raffle_id', raffleId)
            .eq('number', candidate)
            .single();

        if (!data) {
            generatedNumbers.push(candidate);
        }
    }

    if (generatedNumbers.length < quantity) {
        return { success: false, numbers: [], message: 'Erro ao gerar números (conflito de disponibilidade). Tente novamente.' };
    }
    generatedNumbers.sort((a, b) => a - b);

    // Create Purchase Record
    const { data: purchaseData, error: purchaseError } = await supabase
        .from('purchases')
        .insert({
            raffle_id: raffleId,
            name: name,
            cpf: cleanCpf,
            phone: cleanPhone,
            quantity: quantity,
            total_value: quantity * raffle.pricePerNumber
        })
        .select()
        .single();

    if (purchaseError || !purchaseData) {
        console.error(purchaseError);
        return { success: false, numbers: [], message: 'Erro ao registrar compra.' };
    }

    // Create Tickets
    const ticketsPayload = generatedNumbers.map(num => ({
        raffle_id: raffleId,
        purchase_id: purchaseData.id,
        number: num,
        owner_cpf: cleanCpf
    }));

    const { error: ticketsError } = await supabase.from('tickets').insert(ticketsPayload);

    if (ticketsError) {
        console.error(ticketsError);
        return { success: false, numbers: [], message: 'Erro crítico ao gerar bilhetes.' };
    }

    // --- CHECK FOR WINNERS ---
    const { data: wonTickets } = await supabase
        .from('winning_tickets')
        .select('ticket_number, prize_description, id')
        .eq('raffle_id', raffleId)
        .eq('is_active', true) 
        .eq('is_sold', false)
        .in('ticket_number', generatedNumbers);

    const wonPrizes: { number: number; prize: string }[] = [];

    if (wonTickets && wonTickets.length > 0) {
        for (const won of wonTickets) {
            // Update the winning ticket as SOLD with NAME
            await supabase.from('winning_tickets').update({
                is_sold: true,
                purchase_id: purchaseData.id,
                winner_cpf: cleanCpf,
                winner_name: name // Saving the winner name!
            }).eq('id', won.id);

            wonPrizes.push({ number: won.ticket_number, prize: won.prize_description });
        }
    }

    return { success: true, numbers: generatedNumbers, wonPrizes };
  },

  async getMyTickets(cpf: string): Promise<Purchase[]> {
    const cleanCpf = cpf.replace(/\D/g, '');

    const { data: purchases, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .eq('cpf', cleanCpf)
        .order('purchase_date', { ascending: false });

    if (error) return [];

    const fullPurchases = await Promise.all(purchases.map(async (p: any) => {
        const { data: tickets } = await supabase
            .from('tickets')
            .select('number')
            .eq('purchase_id', p.id);

        return {
            id: p.id,
            name: p.name,
            cpf: p.cpf,
            phone: p.phone,
            raffleId: p.raffle_id,
            raffleName: p.raffles?.name,
            quantity: p.quantity,
            totalValue: p.total_value,
            purchaseDate: p.purchase_date,
            ticketNumbers: tickets?.map((t: any) => t.number).sort((a: number, b: number) => a - b) || []
        };
    }));

    return fullPurchases;
  },

  // --- ADMIN METHODS ---

  async adminGetWinningTickets(raffleId: string): Promise<WinningTicket[]> {
      const { data } = await supabase
        .from('winning_tickets')
        .select('*')
        .eq('raffle_id', raffleId)
        .order('ticket_number', { ascending: true });

      if (!data) return [];

      return data.map(t => ({
          id: t.id,
          raffleId: t.raffle_id,
          ticketNumber: t.ticket_number,
          prizeDescription: t.prize_description,
          isActive: t.is_active,
          isSold: t.is_sold,
          winnerName: t.winner_name
      }));
  },

  async adminCreateWinningTicket(raffleId: string, number: number, prize: string) {
      const { error } = await supabase.from('winning_tickets').insert({
          raffle_id: raffleId,
          ticket_number: number,
          prize_description: prize,
          is_active: false // Start inactive (locked) by default
      });
      if (error) throw error;
  },

  async adminToggleWinningTicket(id: string, isActive: boolean) {
      const { error } = await supabase.from('winning_tickets').update({ is_active: isActive }).eq('id', id);
      if (error) throw error;
  },

  async adminDeleteWinningTicket(id: string) {
      const { error } = await supabase.from('winning_tickets').delete().eq('id', id);
      if (error) throw error;
  },

  async adminGetStats() {
      const { data: purchases } = await supabase.from('purchases').select('total_value');
      const totalRevenue = purchases?.reduce((acc, curr) => acc + (curr.total_value || 0), 0) || 0;

      const { count: activeRaffles } = await supabase.from('raffles').select('*', { count: 'exact', head: true }).eq('status', 'ACTIVE');
      const { count: totalTickets } = await supabase.from('tickets').select('*', { count: 'exact', head: true });

      const avgTicket = purchases && purchases.length > 0 ? totalRevenue / purchases.length : 0;

      return { totalRevenue, activeRaffles, totalTickets, avgTicket };
  },

  // Banner Management
  async adminGetBanners() {
      const { data } = await supabase.from('banners').select('*').order('created_at', { ascending: false });
      return data || [];
  },

  async adminCreateBanner(imageUrl: string) {
      const { error } = await supabase.from('banners').insert({ image_url: imageUrl, active: true });
      if (error) throw error;
  },

  async adminDeleteBanner(id: string) {
      const { error } = await supabase.from('banners').delete().eq('id', id);
      if (error) throw error;
  },

  // Raffle Management
  async createRaffle(data: Partial<Raffle>) {
      const payload = {
          name: data.name,
          description: data.description,
          full_description: data.fullDescription,
          image_url: data.imageUrl,
          total_numbers: data.totalNumbers,
          price_per_number: data.pricePerNumber,
          min_purchase: data.minPurchase || 1,
          fake_sold_numbers: data.fakeSoldNumbers || 0,
          status: 'ACTIVE'
      };

      const { data: created, error } = await supabase.from('raffles').insert(payload).select().single();

      if (error) {
          console.error("Erro ao criar rifa:", error);
          throw error;
      }
      return created;
  },

  async updateRaffle(id: string, updates: any) {
     const { error } = await supabase.from('raffles').update(updates).eq('id', id);
     if (error) {
         console.error("Erro ao atualizar rifa:", error);
         throw error;
     }
  },

  // Ticket Management (unchanged)
  async getTicketOwner(raffleId: string, number: number) {
      return await supabase
        .from('tickets')
        .select('*, purchases(phone, cpf, purchase_date, name)')
        .eq('raffle_id', raffleId)
        .eq('number', number)
        .single();
  },

  async adminUpdateTicketOwner(ticketId: string, newCpf: string) {
      const { error } = await supabase.from('tickets').update({ owner_cpf: newCpf }).eq('id', ticketId);
      if (error) throw error;
  },

  // Purchases Management (unchanged)
  async adminGetAllPurchases(limit = 50) {
      const { data, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .order('purchase_date', { ascending: false })
        .limit(limit);

      if(error) throw error;
      return data;
  },

  async adminUpdatePurchase(purchaseId: string, updates: { phone?: string, cpf?: string, name?: string }) {
      const { error } = await supabase.from('purchases').update(updates).eq('id', purchaseId);
      if (error) throw error;

      if (updates.cpf) {
          const { error: ticketError } = await supabase.from('tickets').update({ owner_cpf: updates.cpf }).eq('purchase_id', purchaseId);
          if (ticketError) throw ticketError;
      }
      return { error: null };
  },

  async adminGetRevenueChart() {
      const { data } = await supabase
        .from('purchases')
        .select('total_value, purchase_date')
        .order('purchase_date', { ascending: true });

      if (!data) return [];

      const grouped: Record<string, number> = {};
      data.forEach(p => {
          const date = new Date(p.purchase_date).toLocaleDateString('pt-BR');
          grouped[date] = (grouped[date] || 0) + p.total_value;
      });

      return Object.entries(grouped).map(([date, value]) => ({ date, value }));
  }
};

import React, { useState } from 'react';
import { X, QrCode, Copy, Check, Loader2, AlertCircle, User } from 'lucide-react';
import { Raffle } from '../types';
import { raffleService } from '../services/raffleService';

interface CheckoutModalProps {
  raffle: Raffle;
  quantity: number;
  onClose: () => void;
  onSuccess: (numbers: number[], wonPrizes?: { number: number; prize: string }[]) => void;
}

enum CheckoutStep {
  FORM = 'FORM',
  PAYMENT = 'PAYMENT',
  PROCESSING = 'PROCESSING'
}

export const CheckoutModal: React.FC<CheckoutModalProps> = ({ raffle, quantity, onClose, onSuccess }) => {
  const [step, setStep] = useState<CheckoutStep>(CheckoutStep.FORM);
  const [name, setName] = useState('');
  const [cpf, setCpf] = useState('');
  const [phone, setPhone] = useState('');
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const totalValue = quantity * raffle.pricePerNumber;

  const handleGeneratePix = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || cpf.length < 11 || phone.length < 10) {
      setError('Por favor preencha todos os dados corretamente.');
      return;
    }
    setError(null);
    setStep(CheckoutStep.PAYMENT);

    // Simulate User paying after 5 seconds in demo
    // In real world, we would poll an API endpoint checking payment status
    setTimeout(() => {
        handleConfirmPayment();
    }, 5000);
  };

  const handleConfirmPayment = async () => {
    setStep(CheckoutStep.PROCESSING);
    try {
      const result = await raffleService.purchaseTickets(raffle.id, quantity, name, cpf, phone);
      if (result.success) {
        onSuccess(result.numbers, result.wonPrizes);
      } else {
        setError(result.message || 'Erro ao processar compra.');
        setStep(CheckoutStep.FORM);
      }
    } catch (err) {
      setError('Erro de conexão. Tente novamente.');
      setStep(CheckoutStep.FORM);
    }
  };

  const copyPix = () => {
    // Fake PIX string
    const pixCode = "00020126580014BR.GOV.BCB.PIX0136123e4567-e89b-12d3-a456-426614174000520400005303986540510.005802BR5913BRABO PREMIOS6008BRASILIA62070503***6304E2CA";
    navigator.clipboard.writeText(pixCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm">
      <div className="bg-zinc-900 border border-zinc-800 w-full max-w-md rounded-2xl overflow-hidden shadow-2xl relative">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 text-zinc-500 hover:text-white transition-colors"
        >
          <X size={24} />
        </button>

        <div className="p-6">
          <h2 className="text-2xl font-bold text-white mb-1">Finalizar Compra</h2>
          <p className="text-zinc-400 text-sm mb-6">
            Você está comprando <strong className="text-yellow-500">{quantity} cotas</strong> da rifa <span className="text-white">{raffle.name}</span>
          </p>

          {step === CheckoutStep.FORM && (
            <form onSubmit={handleGeneratePix} className="space-y-4">
               {error && (
                <div className="p-3 bg-red-900/30 border border-red-800 rounded-lg text-red-200 text-sm flex items-center gap-2">
                  <AlertCircle size={16} /> {error}
                </div>
              )}

              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">Nome Completo</label>
                <div className="relative">
                  <User className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
                  <input
                    type="text"
                    required
                    placeholder="Seu nome"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full bg-black border border-zinc-800 rounded-lg pl-10 pr-4 py-3 text-white focus:border-yellow-600 focus:ring-1 focus:ring-yellow-600 outline-none transition-all"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">CPF (apenas números)</label>
                <input
                  type="text"
                  required
                  placeholder="000.000.000-00"
                  value={cpf}
                  onChange={(e) => setCpf(e.target.value)}
                  className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-3 text-white focus:border-yellow-600 focus:ring-1 focus:ring-yellow-600 outline-none transition-all"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-zinc-400 mb-1">Telefone / WhatsApp</label>
                <input
                  type="tel"
                  required
                  placeholder="(00) 00000-0000"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-3 text-white focus:border-yellow-600 focus:ring-1 focus:ring-yellow-600 outline-none transition-all"
                />
              </div>

              <div className="pt-4 border-t border-zinc-800 flex justify-between items-center">
                <span className="text-zinc-400">Total a pagar:</span>
                <span className="text-2xl font-bold text-yellow-500">R$ {totalValue.toFixed(2).replace('.', ',')}</span>
              </div>

              <button 
                type="submit"
                className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl transition-all shadow-lg shadow-green-900/20 active:scale-95 mt-4"
              >
                Gerar Pagamento Pix
              </button>
            </form>
          )}

          {step === CheckoutStep.PAYMENT && (
            <div className="flex flex-col items-center text-center space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="w-16 h-16 bg-green-900/30 rounded-full flex items-center justify-center text-green-500 mb-2">
                <QrCode size={32} />
              </div>

              <div>
                <h3 className="text-lg font-bold text-white">Escaneie o QR Code</h3>
                <p className="text-sm text-zinc-400">Abra o app do seu banco e pague via Pix.</p>
              </div>

              {/* Fake QR Code */}
              <div className="bg-white p-2 rounded-lg">
                <img 
                  src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=BRABO-RIFAS-${raffle.id}-${quantity}`} 
                  alt="QR Code Pix" 
                  className="w-48 h-48"
                />
              </div>

              <div className="w-full">
                <p className="text-xs text-zinc-500 mb-2">Ou copie e cole o código abaixo:</p>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    readOnly 
                    value="00020126580014BR.GOV.BCB.PIX0136123e4567..." 
                    className="flex-1 bg-black border border-zinc-800 rounded-lg px-3 py-2 text-zinc-400 text-sm truncate"
                  />
                  <button 
                    onClick={copyPix}
                    className="bg-zinc-800 hover:bg-zinc-700 text-white px-3 py-2 rounded-lg transition-colors"
                  >
                    {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
                  </button>
                </div>
              </div>

              <div className="text-xs text-yellow-500/80 animate-pulse bg-yellow-900/10 px-4 py-2 rounded-full">
                Aguardando confirmação do pagamento...
              </div>
            </div>
          )}

          {step === CheckoutStep.PROCESSING && (
            <div className="flex flex-col items-center justify-center py-12 space-y-4">
              <Loader2 className="w-12 h-12 text-yellow-500 animate-spin" />
              <p className="text-lg font-medium text-white">Validando pagamento...</p>
              <p className="text-sm text-zinc-500">Isso leva apenas alguns segundos.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Raffle, RaffleStatus, WinningTicket } from '../types';
import { raffleService } from '../services/raffleService';
import { ArrowLeft, Minus, Plus, ShoppingCart, Award, Gift, Trophy, CheckCircle2 } from 'lucide-react';

interface RaffleDetailsProps {
  raffle: Raffle;
  onBack: () => void;
  onBuy: (qty: number) => void;
}

export const RaffleDetails: React.FC<RaffleDetailsProps> = ({ raffle, onBack, onBuy }) => {
  const minPurchase = raffle.minPurchase || 1;
  const [quantity, setQuantity] = useState(minPurchase);
  const [winningTickets, setWinningTickets] = useState<WinningTicket[]>([]);

  // Use max between real and fake
  const displaySold = Math.max(raffle.soldNumbers, raffle.fakeSoldNumbers || 0);
  const percentage = Math.floor((displaySold / raffle.totalNumbers) * 100);

  useEffect(() => {
    raffleService.getPublicWinningTickets(raffle.id).then(setWinningTickets);
  }, [raffle.id]);

  const handleQuantityChange = (val: string) => {
    const num = parseInt(val);
    if (!isNaN(num) && num >= minPurchase) setQuantity(num);
  };

  const increment = () => setQuantity(prev => prev + 1);
  const decrement = () => setQuantity(prev => (prev > minPurchase ? prev - 1 : minPurchase));

  // Dynamic quick options based on min purchase
  const quickOptions = [minPurchase, minPurchase + 5, minPurchase + 10, minPurchase + 50, minPurchase + 100];

  return (
    <div className="animate-in slide-in-from-right-8 fade-in duration-300">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-zinc-400 hover:text-white mb-6 transition-colors"
      >
        <ArrowLeft size={20} />
        Voltar para Home
      </button>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Left: Image - 1350x1080 Aspect Ratio */}
        <div className="space-y-4">
          <div className="w-full aspect-[1350/1080] bg-zinc-900/50 rounded-xl overflow-hidden border border-zinc-800/50">
            <img 
                src={raffle.imageUrl} 
                alt={raffle.name} 
                className="w-full h-full object-contain" 
            />
          </div>

          <div className="bg-zinc-900 rounded-xl p-4 border border-zinc-800">
            <h3 className="text-white font-bold flex items-center gap-2 mb-2">
              <Award className="text-yellow-500" />
              Descrição do Prêmio
            </h3>
            <p className="text-zinc-400 text-sm leading-relaxed whitespace-pre-line">
              {raffle.fullDescription}
            </p>
          </div>
        </div>

        {/* Right: Info & Purchase */}
        <div className="flex flex-col">
          <h1 className="text-3xl font-black text-white mb-2">{raffle.name}</h1>
          <p className="text-zinc-400 mb-6">{raffle.description}</p>

          {/* Progress */}
          <div className="bg-zinc-900 rounded-xl p-5 border border-zinc-800 mb-6">
            <div className="flex justify-between text-sm font-medium mb-2">
              <span className="text-white">Progresso da Ação</span>
              <span className="text-yellow-500 font-bold">{percentage}%</span>
            </div>
            <div className="w-full h-3 bg-black rounded-full overflow-hidden">
              <div 
                className="h-full bg-gradient-to-r from-yellow-600 to-yellow-400 rounded-full transition-all duration-1000"
                style={{ width: `${percentage}%` }}
              ></div>
            </div>
            <p className="text-xs text-zinc-500 mt-2 text-right">
              {displaySold.toLocaleString()} de {raffle.totalNumbers.toLocaleString()} cotas vendidas
            </p>
          </div>

          {/* Winning Tickets Showcase */}
          {winningTickets.length > 0 && (
             <div className="mb-6">
                 <h3 className="text-lg font-bold text-white mb-3 flex items-center gap-2">
                    <Gift className="text-purple-500" size={20} /> Cotas Premiadas
                 </h3>
                 <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                    {winningTickets.map(ticket => (
                        <div 
                            key={ticket.id} 
                            className={`p-2 rounded-lg border flex flex-col items-center text-center ${
                                ticket.isSold 
                                ? 'bg-green-900/10 border-green-900/50' 
                                : 'bg-zinc-900 border-zinc-800'
                            }`}
                        >
                            <div className={`text-xs font-bold mb-1 px-2 py-0.5 rounded-full ${
                                ticket.isSold ? 'bg-green-500 text-black' : 'bg-purple-600 text-white'
                            }`}>
                                {String(ticket.ticketNumber).padStart(5, '0')}
                            </div>
                            <span className="text-xs text-zinc-400 font-medium leading-tight mb-1">{ticket.prizeDescription}</span>

                            {ticket.isSold ? (
                                <div className="text-[10px] text-green-400 font-bold flex flex-col items-center">
                                    <Trophy size={10} className="mb-0.5"/>
                                    <span className="truncate w-full max-w-[100px]">{ticket.winnerName}</span>
                                </div>
                            ) : (
                                <span className="text-[10px] text-zinc-600 font-bold uppercase">Disponível</span>
                            )}
                        </div>
                    ))}
                 </div>
             </div>
          )}

          {raffle.status === RaffleStatus.ACTIVE ? (
            <div className="bg-zinc-900 rounded-xl p-6 border border-yellow-600/30 shadow-lg shadow-yellow-900/10 flex-1 flex flex-col">
              <div className="text-center mb-6">
                <span className="text-zinc-400 text-sm uppercase tracking-wider">Por apenas</span>
                <div className="text-4xl font-black text-white mt-1">
                  R$ {raffle.pricePerNumber.toFixed(2).replace('.', ',')}
                </div>
                {minPurchase > 1 && (
                     <span className="text-yellow-600 text-xs font-bold bg-yellow-900/20 px-2 py-1 rounded mt-2 inline-block">Mínimo: {minPurchase} cotas</span>
                )}
              </div>

              {/* Quantity Selector */}
              <div className="mb-6">
                <label className="block text-sm text-zinc-400 mb-2 font-medium">Quantas cotas você quer?</label>
                <div className="flex items-center gap-3 mb-3">
                  <button onClick={decrement} className="w-12 h-12 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-white transition-colors disabled:opacity-50" disabled={quantity <= minPurchase}>
                    <Minus size={20} />
                  </button>
                  <input 
                    type="number" 
                    value={quantity}
                    onChange={(e) => handleQuantityChange(e.target.value)}
                    className="flex-1 bg-black border border-zinc-700 rounded-lg h-12 text-center text-xl font-bold text-white focus:border-yellow-500 outline-none"
                  />
                  <button onClick={increment} className="w-12 h-12 rounded-lg bg-zinc-800 hover:bg-zinc-700 flex items-center justify-center text-white transition-colors">
                    <Plus size={20} />
                  </button>
                </div>

                {/* Quick select */}
                <div className="flex flex-wrap gap-2">
                  {quickOptions.map(opt => (
                    <button
                      key={opt}
                      onClick={() => setQuantity(opt)}
                      className={`px-3 py-1 rounded-full text-xs font-bold border transition-all ${
                        quantity === opt 
                        ? 'bg-yellow-600 border-yellow-600 text-black' 
                        : 'bg-transparent border-zinc-700 text-zinc-400 hover:border-yellow-500 hover:text-yellow-500'
                      }`}
                    >
                      {opt} cotas
                    </button>
                  ))}
                </div>
              </div>

              <div className="mt-auto pt-6 border-t border-zinc-800">
                <div className="flex justify-between items-end mb-4">
                  <span className="text-zinc-400">Total</span>
                  <span className="text-3xl font-bold text-yellow-500">
                    R$ {(quantity * raffle.pricePerNumber).toFixed(2).replace('.', ',')}
                  </span>
                </div>
                <button 
                  onClick={() => onBuy(quantity)}
                  className="w-full py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl text-lg flex items-center justify-center gap-2 shadow-lg shadow-green-900/30 transition-all hover:scale-[1.02]"
                >
                  <ShoppingCart size={24} />
                  Comprar {quantity} Cotas
                </button>
              </div>
            </div>
          ) : (
            <div className="bg-zinc-800 rounded-xl p-8 flex flex-col items-center justify-center text-center h-full opacity-75">
              <h2 className="text-2xl font-bold text-white mb-2">Ação Finalizada</h2>
              <p className="text-zinc-400">Todas as cotas foram vendidas ou o sorteio já foi realizado.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

