CREATE POLICY "Public Read Raffles" ON raffles FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admin All Raffles" ON raffles;
CREATE POLICY "Admin All Raffles" ON raffles FOR ALL USING (auth.role() = 'authenticated');

