-- 1. Habilitar RLS (Segurança a nível de linha) em todas as tabelas
ALTER TABLE raffles ENABLE ROW LEVEL SECURITY;
ALTER TABLE tickets ENABLE ROW LEVEL SECURITY;
ALTER TABLE purchases ENABLE ROW LEVEL SECURITY;
ALTER TABLE winning_tickets ENABLE ROW LEVEL SECURITY;
ALTER TABLE banners ENABLE ROW LEVEL SECURITY;

-- 2. Políticas de Acesso (Policies)
-- Removemos políticas antigas antes de criar novas para evitar erros de duplicidade

-- RAFFLES
DROP POLICY IF EXISTS "Public Read Raffles" ON raffles;
CREATE POLICY "Public Read Raffles" ON raffles FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admin All Raffles" ON raffles;
CREATE POLICY "Admin All Raffles" ON raffles FOR ALL USING (auth.role() = 'authenticated');

-- BANNERS
DROP POLICY IF EXISTS "Public Read Banners" ON banners;
CREATE POLICY "Public Read Banners" ON banners FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admin All Banners" ON banners;
CREATE POLICY "Admin All Banners" ON banners FOR ALL USING (auth.role() = 'authenticated');

-- TICKETS
DROP POLICY IF EXISTS "Public Read Tickets" ON tickets;
CREATE POLICY "Public Read Tickets" ON tickets FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admin All Tickets" ON tickets;
CREATE POLICY "Admin All Tickets" ON tickets FOR ALL USING (auth.role() = 'authenticated');

-- WINNING TICKETS
DROP POLICY IF EXISTS "Public Read Winning Tickets" ON winning_tickets;
CREATE POLICY "Public Read Winning Tickets" ON winning_tickets FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admin All Winning Tickets" ON winning_tickets;
CREATE POLICY "Admin All Winning Tickets" ON winning_tickets FOR ALL USING (auth.role() = 'authenticated');

-- PURCHASES
DROP POLICY IF EXISTS "Public Insert Purchases" ON purchases;
CREATE POLICY "Public Insert Purchases" ON purchases FOR INSERT WITH CHECK (true);

DROP POLICY IF EXISTS "Public Read Own Purchases" ON purchases;
CREATE POLICY "Public Read Own Purchases" ON purchases FOR SELECT USING (true); 

DROP POLICY IF EXISTS "Admin All Purchases" ON purchases;
CREATE POLICY "Admin All Purchases" ON purchases FOR ALL USING (auth.role() = 'authenticated');

-- 3. CORREÇÃO DE DELETE EM CASCATA
-- Isso permite deletar uma rifa e automaticamente remover compras e tickets associados
-- Sem isso, o banco bloqueia a exclusão por integridade referencial

-- Alterar Purchases para deletar se a Rifa for deletada
ALTER TABLE purchases
DROP CONSTRAINT IF EXISTS purchases_raffle_id_fkey;

ALTER TABLE purchases
ADD CONSTRAINT purchases_raffle_id_fkey
FOREIGN KEY (raffle_id)
REFERENCES raffles(id)
ON DELETE CASCADE;

-- Alterar Tickets para deletar se a Rifa for deletada
ALTER TABLE tickets
DROP CONSTRAINT IF EXISTS tickets_raffle_id_fkey;

ALTER TABLE tickets
ADD CONSTRAINT tickets_raffle_id_fkey
FOREIGN KEY (raffle_id)
REFERENCES raffles(id)
ON DELETE CASCADE;

-- Alterar Tickets para deletar se a Compra for deletada (limpeza extra)
ALTER TABLE tickets
DROP CONSTRAINT IF EXISTS tickets_purchase_id_fkey;

ALTER TABLE tickets
ADD CONSTRAINT tickets_purchase_id_fkey
FOREIGN KEY (purchase_id)
REFERENCES purchases(id)
ON DELETE CASCADE;

-- Alterar Winning Tickets para deletar se a Rifa for deletada
ALTER TABLE winning_tickets
DROP CONSTRAINT IF EXISTS winning_tickets_raffle_id_fkey;

ALTER TABLE winning_tickets
ADD CONSTRAINT winning_tickets_raffle_id_fkey
FOREIGN KEY (raffle_id)
REFERENCES raffles(id)
ON DELETE CASCADE;


-- 4. Função RPC Segura para Compra de Bilhetes
-- Esta função substitui a lógica do frontend, rodando dentro do banco de dados

CREATE OR REPLACE FUNCTION buy_tickets(
  p_raffle_id UUID,
  p_quantity INT,
  p_name TEXT,
  p_cpf TEXT,
  p_phone TEXT,
  p_total_value DECIMAL
) 
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER -- Roda com permissões de admin (para poder inserir tickets)
AS $$
DECLARE
  v_raffle RECORD;
  v_purchase_id UUID;
  v_generated_numbers INT[];
  v_candidate INT;
  v_count INT := 0;
  v_max_attempts INT := 0;
  v_blocked_numbers INT[];
  v_won_prizes JSONB := '[]'::jsonb;
  v_winning_ticket RECORD;
BEGIN
  -- 1. Validar Rifa
  SELECT * INTO v_raffle FROM raffles WHERE id = p_raffle_id;
  IF NOT FOUND THEN
    RETURN json_build_object('success', false, 'message', 'Rifa não encontrada');
  END IF;

  IF v_raffle.status <> 'ACTIVE' THEN
     RETURN json_build_object('success', false, 'message', 'Rifa finalizada ou inativa');
  END IF;

  -- Validar quantidade disponível (estimativa rápida)
  IF (SELECT count(*) FROM tickets WHERE raffle_id = p_raffle_id) + p_quantity > v_raffle.total_numbers THEN
     RETURN json_build_object('success', false, 'message', 'Quantidade de cotas indisponível');
  END IF;

  -- 2. Identificar números bloqueados (Cotas premiadas travadas)
  SELECT array_agg(ticket_number) INTO v_blocked_numbers 
  FROM winning_tickets 
  WHERE raffle_id = p_raffle_id AND is_active = false AND is_sold = false;

  -- 3. Gerar Números Aleatórios Únicos
  -- Loop até encontrar a quantidade desejada de números livres
  WHILE v_count < p_quantity AND v_max_attempts < (p_quantity * 20) LOOP
      v_max_attempts := v_max_attempts + 1;

      -- Gera número randomico entre 0 e total-1
      v_candidate := floor(random() * v_raffle.total_numbers)::INT;

      -- Verifica se já escolhemos este número nesta transação
      IF v_candidate = ANY(v_generated_numbers) THEN
        CONTINUE;
      END IF;

      -- Verifica se é um número bloqueado (Cadeado Fechado)
      IF v_blocked_numbers IS NOT NULL AND v_candidate = ANY(v_blocked_numbers) THEN
        CONTINUE;
      END IF;

      -- Verifica se já existe no banco (Performático)
      PERFORM 1 FROM tickets WHERE raffle_id = p_raffle_id AND number = v_candidate;
      IF NOT FOUND THEN
        v_generated_numbers := array_append(v_generated_numbers, v_candidate);
        v_count := v_count + 1;
      END IF;
  END LOOP;

  IF array_length(v_generated_numbers, 1) < p_quantity THEN
    RETURN json_build_object('success', false, 'message', 'Não foi possível encontrar números consecutivos disponíveis. Tente uma quantidade menor.');
  END IF;

  -- Ordenar números (opcional, para estética)
  SELECT array_agg(x ORDER BY x) INTO v_generated_numbers FROM unnest(v_generated_numbers) x;

  -- 4. Inserir Compra
  INSERT INTO purchases (raffle_id, name, cpf, phone, quantity, total_value, purchase_date)
  VALUES (p_raffle_id, p_name, p_cpf, p_phone, p_quantity, p_total_value, NOW())
  RETURNING id INTO v_purchase_id;

  -- 5. Inserir Bilhetes (Batch Insert)
  INSERT INTO tickets (raffle_id, purchase_id, number, owner_cpf)
  SELECT p_raffle_id, v_purchase_id, unnest(v_generated_numbers), p_cpf;

  -- 6. Verificar Ganhadores Instantâneos (Cotas Premiadas)
  FOR v_winning_ticket IN 
    SELECT * FROM winning_tickets 
    WHERE raffle_id = p_raffle_id 
    AND is_active = true 
    AND is_sold = false 
    AND ticket_number = ANY(v_generated_numbers)
  LOOP
      -- Marcar como vendido
      UPDATE winning_tickets 
      SET is_sold = true, purchase_id = v_purchase_id, winner_cpf = p_cpf, winner_name = p_name
      WHERE id = v_winning_ticket.id;

      -- Adicionar ao JSON de resposta
      v_won_prizes := v_won_prizes || jsonb_build_object(
        'number', v_winning_ticket.ticket_number, 
        'prize', v_winning_ticket.prize_description
      );
  END LOOP;

  -- 7. Retornar Sucesso
  RETURN json_build_object(
    'success', true, 
    'numbers', v_generated_numbers,
    'wonPrizes', v_won_prizes
  );

EXCEPTION WHEN OTHERS THEN
  RETURN json_build_object('success', false, 'message', SQLERRM);
END;
$$;

import { supabase } from './supabaseClient';
import { Raffle, RaffleStatus, Purchase, Banner, WinningTicket, PurchaseResult } from '../types';

export const raffleService = {
  // --- PUBLIC METHODS ---

  async getBanners(): Promise<string[]> {
    const { data, error } = await supabase
      .from('banners')
      .select('image_url')
      .eq('active', true)
      .order('created_at', { ascending: false });

    if (error || !data) {
      return []; 
    }
    return data.map(b => b.image_url);
  },

  async getAllRaffles(): Promise<Raffle[]> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw error;

    const rafflesWithCount = await Promise.all(data.map(async (r: any) => {
        const { count } = await supabase
            .from('tickets')
            .select('*', { count: 'exact', head: true })
            .eq('raffle_id', r.id);

        return {
            id: r.id,
            name: r.name,
            description: r.description,
            fullDescription: r.full_description,
            imageUrl: r.image_url,
            totalNumbers: r.total_numbers,
            soldNumbers: count || 0,
            fakeSoldNumbers: r.fake_sold_numbers || 0,
            pricePerNumber: r.price_per_number,
            minPurchase: r.min_purchase || 1,
            status: r.status as RaffleStatus,
            winnerNumber: r.winner_number,
            winnerName: r.winner_name
        };
    }));

    return rafflesWithCount;
  },

  async getRaffleById(id: string): Promise<Raffle | undefined> {
    const { data, error } = await supabase
      .from('raffles')
      .select('*')
      .eq('id', id)
      .single();

    if (error || !data) return undefined;

    const { count } = await supabase
        .from('tickets')
        .select('*', { count: 'exact', head: true })
        .eq('raffle_id', id);

    return {
        id: data.id,
        name: data.name,
        description: data.description,
        fullDescription: data.full_description,
        imageUrl: data.image_url,
        totalNumbers: data.total_numbers,
        soldNumbers: count || 0,
        fakeSoldNumbers: data.fake_sold_numbers || 0,
        pricePerNumber: data.price_per_number,
        minPurchase: data.min_purchase || 1,
        status: data.status as RaffleStatus,
        winnerNumber: data.winner_number,
        winnerName: data.winner_name
    };
  },

  async getPublicWinningTickets(raffleId: string): Promise<WinningTicket[]> {
      const { data, error } = await supabase
        .from('winning_tickets')
        .select('id, ticket_number, prize_description, is_sold, winner_name, is_active, raffle_id')
        .eq('raffle_id', raffleId)
        .order('ticket_number', { ascending: true });

      if (error || !data) return [];

      return data.map(t => ({
          id: t.id,
          raffleId: t.raffle_id,
          ticketNumber: t.ticket_number,
          prizeDescription: t.prize_description,
          isActive: t.is_active,
          isSold: t.is_sold,
          winnerName: t.winner_name
      }));
  },

  // NEW: Get recent winners across all raffles for the homepage
  async getRecentGlobalWinners(limit = 10): Promise<any[]> {
    const { data, error } = await supabase
        .from('winning_tickets')
        .select('winner_name, prize_description, raffles(name)')
        .eq('is_sold', true)
        .order('id', { ascending: false }) // Assuming ID increments roughly with time or use a updated_at if available
        .limit(limit);

    if (error || !data) return [];

    return data.map((item: any) => ({
        name: item.winner_name,
        prize: item.prize_description,
        raffleName: item.raffles?.name,
        type: 'INSTANT' // To distinguish from main raffle winners
    }));
  },

  // --- SECURE PURCHASE METHOD ---
  async purchaseTickets(
    raffleId: string,
    quantity: number,
    name: string,
    cpf: string,
    phone: string
  ): Promise<PurchaseResult> {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    // Get current price to send to backend (extra validation happens on backend)
    const raffle = await this.getRaffleById(raffleId);
    if (!raffle) return { success: false, numbers: [], message: 'Rifa inválida.' };

    const totalValue = quantity * raffle.pricePerNumber;

    // Call the Postgres RPC function 'buy_tickets'
    // This moves all logic (random generation, availability check, database insertion) to the server side.
    const { data, error } = await supabase.rpc('buy_tickets', {
        p_raffle_id: raffleId,
        p_quantity: quantity,
        p_name: name,
        p_cpf: cleanCpf,
        p_phone: cleanPhone,
        p_total_value: totalValue
    });

    if (error) {
        console.error("RPC Error:", error);
        return { success: false, numbers: [], message: 'Erro ao processar compra no servidor.' };
    }

    if (!data.success) {
        return { success: false, numbers: [], message: data.message };
    }

    // Convert wonPrizes from JSONB if exists
    const wonPrizes = data.wonPrizes ? data.wonPrizes : [];

    return { 
        success: true, 
        numbers: data.numbers, 
        wonPrizes: wonPrizes
    };
  },

  async getMyTickets(cpf: string): Promise<Purchase[]> {
    const cleanCpf = cpf.replace(/\D/g, '');

    const { data: purchases, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .eq('cpf', cleanCpf)
        .order('purchase_date', { ascending: false });

    if (error) return [];

    const fullPurchases = await Promise.all(purchases.map(async (p: any) => {
        const { data: tickets } = await supabase
            .from('tickets')
            .select('number')
            .eq('purchase_id', p.id);

        return {
            id: p.id,
            name: p.name,
            cpf: p.cpf,
            phone: p.phone,
            raffleId: p.raffle_id,
            raffleName: p.raffles?.name,
            quantity: p.quantity,
            totalValue: p.total_value,
            purchaseDate: p.purchase_date,
            ticketNumbers: tickets?.map((t: any) => t.number).sort((a: number, b: number) => a - b) || []
        };
    }));

    return fullPurchases;
  },

  // --- ADMIN METHODS ---

  async adminGetWinningTickets(raffleId: string): Promise<WinningTicket[]> {
      const { data } = await supabase
        .from('winning_tickets')
        .select('*')
        .eq('raffle_id', raffleId)
        .order('ticket_number', { ascending: true });

      if (!data) return [];

      return data.map(t => ({
          id: t.id,
          raffleId: t.raffle_id,
          ticketNumber: t.ticket_number,
          prizeDescription: t.prize_description,
          isActive: t.is_active,
          isSold: t.is_sold,
          winnerName: t.winner_name
      }));
  },

  async adminCreateWinningTicket(raffleId: string, number: number, prize: string) {
      const { error } = await supabase.from('winning_tickets').insert({
          raffle_id: raffleId,
          ticket_number: number,
          prize_description: prize,
          is_active: false // Start inactive (locked) by default
      });
      if (error) throw error;
  },

  async adminToggleWinningTicket(id: string, isActive: boolean) {
      const { error } = await supabase.from('winning_tickets').update({ is_active: isActive }).eq('id', id);
      if (error) throw error;
  },

  async adminDeleteWinningTicket(id: string) {
      const { error } = await supabase.from('winning_tickets').delete().eq('id', id);
      if (error) throw error;
  },

  async adminManualAssignWinner(winningTicketId: string, raffleId: string, number: number, name: string, cpf: string, phone: string) {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    const { data: existing } = await supabase.from('tickets').select('id').eq('raffle_id', raffleId).eq('number', number).single();
    if (existing) {
        throw new Error('Este número já foi vendido para outra pessoa.');
    }

    const { data: purchase, error: pError } = await supabase.from('purchases').insert({
        raffle_id: raffleId,
        name: name,
        cpf: cleanCpf,
        phone: cleanPhone,
        quantity: 1,
        total_value: 0,
        purchase_date: new Date().toISOString()
    }).select().single();

    if (pError) throw pError;

    const { error: tError } = await supabase.from('tickets').insert({
        raffle_id: raffleId,
        purchase_id: purchase.id,
        number: number,
        owner_cpf: cleanCpf
    });

    if (tError) throw tError;

    const { error: wError } = await supabase.from('winning_tickets').update({
        is_sold: true,
        winner_name: name,
        winner_cpf: cleanCpf,
        purchase_id: purchase.id
    }).eq('id', winningTicketId);

    if (wError) throw wError;
  },

  async adminCreateManualTicket(raffleId: string, number: number, name: string, cpf: string, phone: string) {
    const cleanCpf = cpf.replace(/\D/g, '');
    const cleanPhone = phone.replace(/\D/g, '');

    const { data: existing } = await supabase.from('tickets').select('id').eq('raffle_id', raffleId).eq('number', number).single();
    if (existing) {
        throw new Error('Este número já foi vendido.');
    }

    const { data: purchase, error: pError } = await supabase.from('purchases').insert({
        raffle_id: raffleId,
        name: name,
        cpf: cleanCpf,
        phone: cleanPhone,
        quantity: 1,
        total_value: 0,
        purchase_date: new Date().toISOString()
    }).select().single();

    if (pError) throw pError;

    const { error: tError } = await supabase.from('tickets').insert({
        raffle_id: raffleId,
        purchase_id: purchase.id,
        number: number,
        owner_cpf: cleanCpf
    });

    if (tError) throw tError;

    const { data: winningTicket } = await supabase.from('winning_tickets').select('id').eq('raffle_id', raffleId).eq('ticket_number', number).single();

    if (winningTicket) {
        await supabase.from('winning_tickets').update({
            is_sold: true,
            winner_name: name,
            winner_cpf: cleanCpf,
            purchase_id: purchase.id
        }).eq('id', winningTicket.id);
    }

    return purchase;
  },

  async adminGetBanners() {
      const { data } = await supabase.from('banners').select('*').order('created_at', { ascending: false });
      return data || [];
  },

  async adminCreateBanner(imageUrl: string) {
      const { error } = await supabase.from('banners').insert({ image_url: imageUrl, active: true });
      if (error) throw error;
  },

  async adminDeleteBanner(id: string) {
      const { error } = await supabase.from('banners').delete().eq('id', id);
      if (error) throw error;
  },

  async createRaffle(data: Partial<Raffle>) {
      const payload = {
          name: data.name,
          description: data.description,
          full_description: data.fullDescription,
          image_url: data.imageUrl,
          total_numbers: data.totalNumbers,
          price_per_number: data.pricePerNumber,
          min_purchase: data.minPurchase || 1,
          fake_sold_numbers: data.fakeSoldNumbers || 0,
          status: 'ACTIVE'
      };

      const { data: created, error } = await supabase.from('raffles').insert(payload).select().single();

      if (error) {
          console.error("Erro ao criar rifa:", error);
          throw error;
      }
      return created;
  },

  async updateRaffle(id: string, updates: any) {
     const { error } = await supabase.from('raffles').update(updates).eq('id', id);
     if (error) {
         console.error("Erro ao atualizar rifa:", error);
         throw error;
     }
  },

  async getTicketOwner(raffleId: string, number: number) {
      return await supabase
        .from('tickets')
        .select('*, purchases(phone, cpf, purchase_date, name)')
        .eq('raffle_id', raffleId)
        .eq('number', number)
        .single();
  },

  async adminUpdateTicketOwner(ticketId: string, newCpf: string) {
      const { error } = await supabase.from('tickets').update({ owner_cpf: newCpf }).eq('id', ticketId);
      if (error) throw error;
  },

  async adminGetAllPurchases(limit = 50) {
      const { data, error } = await supabase
        .from('purchases')
        .select('*, raffles(name)')
        .order('purchase_date', { ascending: false })
        .limit(limit);

      if(error) throw error;
      return data;
  },

  async adminUpdatePurchase(purchaseId: string, updates: { phone?: string, cpf?: string, name?: string }) {
      const { error } = await supabase.from('purchases').update(updates).eq('id', purchaseId);
      if (error) throw error;

      if (updates.cpf) {
          const { error: ticketError } = await supabase.from('tickets').update({ owner_cpf: updates.cpf }).eq('purchase_id', purchaseId);
          if (ticketError) throw ticketError;
      }
      return { error: null };
  },

  async adminGetTicketsByPurchase(purchaseId: string): Promise<number[]> {
      const { data, error } = await supabase
        .from('tickets')
        .select('number')
        .eq('purchase_id', purchaseId)
        .order('number', { ascending: true });

      if (error || !data) return [];
      return data.map(t => t.number);
  },

  // NEW METHOD: Flexible Dashboard Stats with Date Filters
  async getDashboardStats(startDate: string | null, endDate: string | null) {
      let query = supabase.from('purchases').select('total_value, purchase_date, quantity');

      if (startDate) {
          query = query.gte('purchase_date', startDate);
      }
      if (endDate) {
          query = query.lte('purchase_date', endDate);
      }

      const { data: purchases, error } = await query;
      if (error || !purchases) return { totalRevenue: 0, salesCount: 0, avgTicket: 0, chartData: [], activeRaffles: 0 };

      // Calculate aggregates
      const totalRevenue = purchases.reduce((acc, p) => acc + (p.total_value || 0), 0);
      const salesCount = purchases.length;
      const avgTicket = salesCount > 0 ? totalRevenue / salesCount : 0;

      // Group for chart (Group by Day)
      const grouped: Record<string, number> = {};
      purchases.forEach(p => {
          // If viewing "Today" only (start == end and it's today), maybe we could group by hour? 
          // For simplicity, let's keep daily grouping or "today" just shows one bar if filtered strict.
          // To make it look "robust", if the range is small (1 day), we group by hour.

          let key;
          const dateObj = new Date(p.purchase_date);

          if (startDate && endDate && startDate.split('T')[0] === endDate.split('T')[0]) {
              // Group by Hour if filtering single day
              key = `${dateObj.getHours()}h`;
          } else {
              // Group by Date
              key = dateObj.toLocaleDateString('pt-BR');
          }

          grouped[key] = (grouped[key] || 0) + p.total_value;
      });

      // Fill gaps? Not strictly necessary for this MVP but looks better. 
      // We'll just map existing data.
      const chartData = Object.entries(grouped).map(([name, value]) => ({ name, value }));

      // Fetch active raffles count (snapshot, not historical)
      const { count: activeRaffles } = await supabase
        .from('raffles')
        .select('*', { count: 'exact', head: true })
        .eq('status', 'ACTIVE');

      return {
          totalRevenue,
          salesCount,
          avgTicket,
          chartData,
          activeRaffles: activeRaffles || 0
      };
  }
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { raffleService } from '../services/raffleService';
import { Raffle, Purchase, Banner, WinningTicket } from '../types';
import { 
  LayoutDashboard, 
  Plus, 
  Edit, 
  Trash2, 
  Ticket, 
  DollarSign, 
  Users, 
  LogOut, 
  Save, 
  X,
  Search,
  Trophy,
  Loader2,
  Lock,
  Image as ImageIcon,
  TrendingUp,
  ShoppingBag,
  RefreshCw,
  AlertTriangle,
  Unlock,
  Gift,
  Eye,
  UserPlus,
  Calendar,
  Filter
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';

type DateFilter = 'today' | 'yesterday' | '7days' | '30days' | 'all' | 'custom';

export const AdminPanel: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  const [session, setSession] = useState<any>(null);
  const [loadingSession, setLoadingSession] = useState(true);

  // Login State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [loggingIn, setLoggingIn] = useState(false);

  // Tabs
  const [activeTab, setActiveTab] = useState<'dashboard' | 'raffles' | 'tickets' | 'sales' | 'site'>('dashboard');

  // Dashboard Logic
  const [dateFilter, setDateFilter] = useState<DateFilter>('today');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [stats, setStats] = useState({ totalRevenue: 0, activeRaffles: 0, salesCount: 0, avgTicket: 0 });
  const [chartData, setChartData] = useState<any[]>([]);
  const [raffles, setRaffles] = useState<Raffle[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  // Raffle Form
  const [isEditing, setIsEditing] = useState<Raffle | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [formData, setFormData] = useState<any>({});
  const [savingRaffle, setSavingRaffle] = useState(false);
  const [manualProgressPercent, setManualProgressPercent] = useState<number | string>('');

  // Winning Tickets State
  const [winningTickets, setWinningTickets] = useState<WinningTicket[]>([]);
  const [newWinningTicket, setNewWinningTicket] = useState({ number: '', prize: '' });

  // Manual Winner Assignment State (Inside Raffle Edit)
  const [assigningWinner, setAssigningWinner] = useState<WinningTicket | null>(null);
  const [assignForm, setAssignForm] = useState({ name: '', cpf: '', phone: '' });

  // Ticket Manager (Search & Manual Creation)
  const [searchTicket, setSearchTicket] = useState({ raffleId: '', number: '' });
  const [foundTicket, setFoundTicket] = useState<any>(null);
  const [newOwnerCpf, setNewOwnerCpf] = useState('');
  const [manualTicketForm, setManualTicketForm] = useState({ name: '', cpf: '', phone: '' });

  // Sales Manager
  const [purchases, setPurchases] = useState<any[]>([]);
  const [editPurchase, setEditPurchase] = useState<any>(null);
  const [viewingPurchaseTickets, setViewingPurchaseTickets] = useState<{numbers: number[], info: any} | null>(null);

  // Site Manager (Banners)
  const [banners, setBanners] = useState<any[]>([]);
  const [newBannerUrl, setNewBannerUrl] = useState('');

  // --- Input Formatters ---
  const formatCPF = (val: string) => {
    let value = val.replace(/\D/g, '');
    if (value.length > 11) value = value.slice(0, 11);
    value = value.replace(/(\d{3})(\d)/, '$1.$2');
    value = value.replace(/(\d{3})(\d)/, '$1.$2');
    value = value.replace(/(\d{3})(\d{1,2})$/, '$1-$2');
    return value;
  };

  const formatPhone = (val: string) => {
    let value = val.replace(/\D/g, '');
    if (value.length > 11) value = value.slice(0, 11);
    if (value.length > 10) {
      value = value.replace(/^(\d{2})(\d{5})(\d{4}).*/, '($1) $2-$3');
    } else if (value.length > 5) {
      value = value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, '($1) $2-$3');
    } else if (value.length > 2) {
      value = value.replace(/^(\d{2})(\d{0,5}).*/, '($1) $2');
    }
    return value;
  };

  const formatName = (val: string) => {
    return val.replace(/[^A-Za-zÀ-ÖØ-öø-ÿ\s]/g, '');
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoadingSession(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session && activeTab === 'dashboard') {
      loadDashboardWithFilters();
    }
  }, [session, activeTab, dateFilter, customStart, customEnd]); // Reload when filters change

  const loadDashboardWithFilters = async () => {
    setLoadingData(true);
    try {
        // Calculate date ranges
        const now = new Date();
        let start: Date | null = null;
        let end: Date | null = new Date(); // Default end is now

        switch (dateFilter) {
            case 'today':
                start = new Date();
                start.setHours(0, 0, 0, 0);
                end.setHours(23, 59, 59, 999);
                break;
            case 'yesterday':
                start = new Date();
                start.setDate(start.getDate() - 1);
                start.setHours(0, 0, 0, 0);
                end = new Date(start);
                end.setHours(23, 59, 59, 999);
                break;
            case '7days':
                start = new Date();
                start.setDate(start.getDate() - 7);
                start.setHours(0, 0, 0, 0);
                break;
            case '30days':
                start = new Date();
                start.setDate(start.getDate() - 30);
                start.setHours(0, 0, 0, 0);
                break;
            case 'custom':
                if (customStart) start = new Date(customStart + 'T00:00:00');
                if (customEnd) end = new Date(customEnd + 'T23:59:59');
                break;
            case 'all':
                start = null;
                end = null;
                break;
        }

        const sISO = start ? start.toISOString() : null;
        const eISO = end ? end.toISOString() : null;

        const data = await raffleService.getDashboardStats(sISO, eISO);
        setStats({
            totalRevenue: data.totalRevenue,
            activeRaffles: data.activeRaffles,
            salesCount: data.salesCount,
            avgTicket: data.avgTicket
        });
        setChartData(data.chartData);

        // Also refresh raffle list for the management part
        if (raffles.length === 0) {
            const r = await raffleService.getAllRaffles();
            setRaffles(r);
        }

    } catch (error) {
        console.error("Erro ao carregar dashboard", error);
    } finally {
        setLoadingData(false);
    }
  };

  // --- TAB LOADERS ---
  useEffect(() => {
      if(!session) return;
      if (activeTab === 'sales') loadPurchases();
      if (activeTab === 'site') loadBanners();
  }, [activeTab]);

  const loadPurchases = async () => {
      setLoadingData(true);
      try {
          const data = await raffleService.adminGetAllPurchases(100);
          setPurchases(data || []);
      } catch(e) { console.error(e); } 
      finally { setLoadingData(false); }
  };

  const loadBanners = async () => {
      try {
          const data = await raffleService.adminGetBanners();
          setBanners(data);
      } catch(e) { console.error(e); }
  };

  const loadWinningTickets = async (raffleId: string) => {
      try {
          const tickets = await raffleService.adminGetWinningTickets(raffleId);
          setWinningTickets(tickets);
      } catch (e) { console.error(e); }
  };

  // --- HELPERS ---
  const handleOpenEdit = (raffle: Raffle) => {
      setIsEditing(raffle);
      setIsCreating(false);
      setFormData(raffle);
      loadWinningTickets(raffle.id);

      // Calculate current visible percentage
      const currentSold = Math.max(raffle.soldNumbers, raffle.fakeSoldNumbers || 0);
      const percent = Math.floor((currentSold / raffle.totalNumbers) * 100);
      setManualProgressPercent(percent);
  };

  const handleOpenCreate = () => {
      setIsCreating(true);
      setIsEditing(null);
      setWinningTickets([]);
      setFormData({ totalNumbers: 1000, pricePerNumber: 0.99, minPurchase: 1 });
      setManualProgressPercent(0);
  };

  // --- ACTIONS ---

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoggingIn(true);
    setLoginError('');
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setLoginError('Email ou senha inválidos.');
    setLoggingIn(false);
  };

  const handleSaveRaffle = async (e: React.FormEvent) => {
      e.preventDefault();
      setSavingRaffle(true);
      try {
          // Calculate fake sold numbers based on percentage input
          const percent = parseFloat(manualProgressPercent.toString()) || 0;
          const total = parseInt(formData.totalNumbers);
          const fakeSold = Math.floor((percent / 100) * total);

          const payload = {
            fakeSoldNumbers: fakeSold,
            ...formData
          };

          if (isCreating) {
              await raffleService.createRaffle(payload);
          } else if (isEditing) {
              await raffleService.updateRaffle(isEditing.id, {
                  name: formData.name,
                  description: formData.description,
                  full_description: formData.fullDescription,
                  image_url: formData.imageUrl,
                  price_per_number: formData.pricePerNumber,
                  min_purchase: formData.minPurchase,
                  status: formData.status,
                  fake_sold_numbers: fakeSold,
                  winner_number: formData.winnerNumber || null,
                  winner_name: formData.winnerName || null
              });
          }
          alert('Rifa salva com sucesso!');
          setIsCreating(false);
          setIsEditing(null);
          setFormData({});
          loadDashboardWithFilters(); // Refresh
      } catch (err: any) {
          console.error(err);
          alert(`Erro ao salvar rifa: ${err.message || 'Erro desconhecido'}.`);
      } finally {
          setSavingRaffle(false);
      }
  };

  const handleAddWinningTicket = async () => {
      if (!isEditing) return alert('Salve a rifa antes de adicionar bilhetes premiados.');
      if (!newWinningTicket.number || !newWinningTicket.prize) return alert('Preencha o número e o prêmio.');

      try {
          await raffleService.adminCreateWinningTicket(isEditing.id, parseInt(newWinningTicket.number), newWinningTicket.prize);
          setNewWinningTicket({ number: '', prize: '' });
          loadWinningTickets(isEditing.id);
      } catch(e: any) {
         alert('Erro ao criar bilhete premiado: ' + e.message);
      }
  };

  const handleToggleWinningTicket = async (id: string, currentStatus: boolean) => {
      try {
          await raffleService.adminToggleWinningTicket(id, !currentStatus);
          loadWinningTickets(isEditing!.id);
      } catch(e: any) {
          alert('Erro: ' + e.message);
      }
  };

  const handleDeleteWinningTicket = async (id: string) => {
      if(!confirm('Remover este bilhete premiado?')) return;
      try {
          await raffleService.adminDeleteWinningTicket(id);
          loadWinningTickets(isEditing!.id);
      } catch(e: any) {
         alert('Erro: ' + e.message);
      }
  };

  const handleOpenAssignWinner = (ticket: WinningTicket) => {
    setAssigningWinner(ticket);
    setAssignForm({ name: '', cpf: '', phone: '' });
  };

  const handleSubmitAssignWinner = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!assigningWinner || !isEditing) return;

    try {
        await raffleService.adminManualAssignWinner(
            assigningWinner.id,
            isEditing.id,
            assigningWinner.ticketNumber,
            assignForm.name,
            assignForm.cpf,
            assignForm.phone
        );
        alert(`Sucesso! O bilhete ${assigningWinner.ticketNumber} foi atribuído a ${assignForm.name}.`);
        setAssigningWinner(null);
        loadWinningTickets(isEditing.id);
    } catch(e: any) {
        alert('Erro ao atribuir ganhador: ' + e.message);
    }
  };

  const handleDeleteRaffle = async (id: string) => {
      if(!confirm('ATENÇÃO: Deletar uma rifa apaga todo histórico de vendas dela. Confirmar?')) return;
      const { error } = await supabase.from('raffles').delete().eq('id', id);
      if (error) alert('Erro ao deletar: ' + error.message);
      else loadDashboardWithFilters();
  };

  const handleSearchTicket = async (e: React.FormEvent) => {
      e.preventDefault();
      setFoundTicket(null);
      setManualTicketForm({ name: '', cpf: '', phone: '' });
      const { data, error } = await raffleService.getTicketOwner(searchTicket.raffleId, parseInt(searchTicket.number));
      if(error || !data) setFoundTicket({ error: 'Bilhete não encontrado.' });
      else setFoundTicket(data);
  };

  const handleUpdateTicketOwner = async () => {
      if (!foundTicket || !foundTicket.id) return;
      if (!newOwnerCpf || newOwnerCpf.length < 11) return alert('CPF inválido');

      try {
          await raffleService.adminUpdateTicketOwner(foundTicket.id, newOwnerCpf);
          alert('Dono do bilhete atualizado com sucesso!');
          setFoundTicket(prev => ({...prev, owner_cpf: newOwnerCpf}));
          setNewOwnerCpf('');
      } catch(e: any) {
          alert('Erro ao atualizar dono: ' + e.message);
      }
  };

  const handleCreateManualTicket = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!searchTicket.raffleId || !searchTicket.number) return;

      try {
          await raffleService.adminCreateManualTicket(
              searchTicket.raffleId,
              parseInt(searchTicket.number),
              manualTicketForm.name,
              manualTicketForm.cpf,
              manualTicketForm.phone
          );
          alert(`Bilhete #${searchTicket.number} criado com sucesso!`);
          handleSearchTicket(e); // Refresh search to show the ticket
      } catch(e: any) {
          alert('Erro ao criar bilhete: ' + e.message);
      }
  };

  const handleUpdatePurchase = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!editPurchase) return;
      try {
          await raffleService.adminUpdatePurchase(editPurchase.id, { 
              name: editPurchase.name,
              phone: editPurchase.phone, 
              cpf: editPurchase.cpf 
          });
          setEditPurchase(null);
          loadPurchases();
          alert('Dados da compra atualizados.');
      } catch(e: any) {
          alert('Erro ao atualizar compra: ' + e.message);
      }
  };

  const handleAddBanner = async (e: React.FormEvent) => {
      e.preventDefault();
      if(!newBannerUrl) return;
      try {
          await raffleService.adminCreateBanner(newBannerUrl);
          setNewBannerUrl('');
          loadBanners();
      } catch(e: any) {
          alert('Erro ao adicionar banner: ' + e.message);
      }
  };

  const handleDeleteBanner = async (id: string) => {
      if(!confirm('Remover banner?')) return;
      try {
          await raffleService.adminDeleteBanner(id);
          loadBanners();
      } catch(e: any) {
          alert('Erro ao remover banner: ' + e.message);
      }
  };

  const handleViewTickets = async (purchase: any) => {
      try {
          const numbers = await raffleService.adminGetTicketsByPurchase(purchase.id);
          setViewingPurchaseTickets({
              numbers,
              info: purchase
          });
      } catch(e: any) {
          alert('Erro ao buscar bilhetes: ' + e.message);
      }
  };


  // --- VIEW ---

  if (loadingSession) return <div className="min-h-screen bg-zinc-950 flex items-center justify-center text-white"><Loader2 className="animate-spin" /></div>;

  if (!session) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-zinc-950 p-4">
        <form onSubmit={handleLogin} className="bg-zinc-900 p-8 rounded-2xl border border-zinc-800 w-full max-w-md shadow-2xl">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-yellow-900/20 rounded-full"><Lock className="w-8 h-8 text-yellow-500" /></div>
          </div>
          <h2 className="text-2xl font-bold text-white mb-2 text-center">Admin Pro</h2>
          {loginError && <div className="bg-red-900/30 border border-red-800 text-red-200 p-3 rounded mb-4 text-sm text-center">{loginError}</div>}
          <div className="space-y-4">
            <input type="email" placeholder="admin@brabo.com" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-black border border-zinc-700 rounded-lg p-3 text-white focus:border-yellow-600 outline-none" />
            <input type="password" placeholder="••••••••" value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-black border border-zinc-700 rounded-lg p-3 text-white focus:border-yellow-600 outline-none" />
          </div>
          <button disabled={loggingIn} className="w-full bg-yellow-600 hover:bg-yellow-500 text-black font-bold py-3 rounded-lg mt-6 flex justify-center">
            {loggingIn ? <Loader2 className="animate-spin" /> : 'Entrar'}
          </button>
          <button type="button" onClick={onExit} className="w-full mt-4 text-zinc-500 text-sm">Voltar ao site</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col md:flex-row text-white font-sans">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-zinc-900 border-r border-zinc-800 flex flex-col z-20">
        <div className="p-6 border-b border-zinc-800">
            <h1 className="text-xl font-bold text-yellow-500 tracking-wider">BRABO CMS</h1>
            <p className="text-xs text-zinc-500">v2.0 Ultimate</p>
        </div>

        <nav className="flex-1 p-4 space-y-1">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Faturamento' },
            { id: 'raffles', icon: Ticket, label: 'Gerenciar Rifas' },
            { id: 'sales', icon: ShoppingBag, label: 'Vendas & Leads' },
            { id: 'tickets', icon: Users, label: 'Editar Bilhetes' },
            { id: 'site', icon: ImageIcon, label: 'Configurar Site' },
          ].map((item) => (
             <button 
                key={item.id}
                onClick={() => setActiveTab(item.id as any)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${activeTab === item.id ? 'bg-yellow-600 text-black font-bold shadow-lg shadow-yellow-900/20' : 'text-zinc-400 hover:bg-zinc-800 hover:text-white'}`}
              >
                <item.icon size={18} /> {item.label}
              </button>
          ))}
        </nav>

        <div className="p-4 border-t border-zinc-800">
            <div className="flex items-center gap-3 mb-4 px-2">
                <div className="w-8 h-8 rounded-full bg-zinc-800 flex items-center justify-center text-xs font-bold">AD</div>
